cmmc5pkp600233v02rlo8nqvx	cmmbeuib8000m3v02t0xw15l9	What is the minimum score required to pass the Florida State Licensing Exam?	{70%,75%,80%,85%}	1	{"correct": "To become a licensed real estate sales associate in Florida, you must score at least 75% on the Florida State Licensing Exam.", "incorrect": ["While 70% might be a passing grade for other types of tests, the state exam requires a higher threshold of 75%.", "", "Although aiming for an 80% is great for your confidence, the strict legal minimum required to pass the state exam is 75%.", "Although aiming for a 100% is great for your confidence, the strict legal minimum required to pass the state exam is 75%."]}	2	chapter	2026-03-04 14:53:26.918	2026-03-04 15:09:08.861	\N	\N	\N	\N	/audio/1772636944680-To_become_a_licensed.mp3	/timestamps/1772636944680-To_become_a_licensed.timestamps.json	["/audio/1772636946088-While_70__might_be_a.mp3", "", "/audio/1772636947309-Although_aiming_for_.mp3", "/audio/1772636948653-Although_aiming_for_.mp3"]	["/timestamps/1772636946088-While_70__might_be_a.timestamps.json", "", "/timestamps/1772636947309-Although_aiming_for_.timestamps.json", "/timestamps/1772636948653-Although_aiming_for_.timestamps.json"]	["/audio/1772636941300-70_.mp3", "/audio/1772636941871-75_.mp3", "/audio/1772636942427-80_.mp3", "/audio/1772636943082-85_.mp3"]	["/timestamps/1772636941300-70_.timestamps.json", "/timestamps/1772636941871-75_.timestamps.json", "/timestamps/1772636942427-80_.timestamps.json", "/timestamps/1772636943082-85_.timestamps.json"]	/audio/1772636940628-What_is_the_minimum_.mp3	/timestamps/1772636940628-What_is_the_minimum_.timestamps.json
