cmmbfc331000w3v02kea7onsn	cmmbeuib8000m3v02t0xw15l9	How many hours of state-approved pre-licensing education must a standard candidate complete before becoming eligible to take the Florida sales associate exam?	{"45 hours","60 hours","63 hours","72 hours"}	2	{"correct": "The Florida Real Estate Commission requires standard applicants to complete a 63-hour Sales Associate Pre-Licensing Course (Course I) from a state-approved provider.", "incorrect": ["45 hours is the requirement for the post-licensing course that must be completed before the first license renewal.", "60 hours are not the correct required hours for the standard Florida sales associate pre-licensing course.", "", "72 hours is the requirement for the broker pre-licensing course."]}	3	chapter	2026-03-04 02:35:07.549	2026-03-04 15:09:18.035	\N	\N	\N	\N	/audio/1772636954800-The_Florida_Real_Est.mp3	/timestamps/1772636954800-The_Florida_Real_Est.timestamps.json	["/audio/1772636955976-45_hours_is_the_requ.mp3", "/audio/1772636957050-60_hours_are_not_the.mp3", "", "/audio/1772636957885-72_hours_is_the_requ.mp3"]	["/timestamps/1772636955976-45_hours_is_the_requ.timestamps.json", "/timestamps/1772636957050-60_hours_are_not_the.timestamps.json", "", "/timestamps/1772636957885-72_hours_is_the_requ.timestamps.json"]	["/audio/1772636951339-45_hours.mp3", "/audio/1772636951974-60_hours.mp3", "/audio/1772636952493-63_hours.mp3", "/audio/1772636953304-72_hours.mp3"]	["/timestamps/1772636951339-45_hours.timestamps.json", "/timestamps/1772636951974-60_hours.timestamps.json", "/timestamps/1772636952493-63_hours.timestamps.json", "/timestamps/1772636953304-72_hours.timestamps.json"]	/audio/1772636950556-How_many_hours_of_st.mp3	/timestamps/1772636950556-How_many_hours_of_st.timestamps.json
