cmmc5t29400253v02yv6pohkm	cmmbeuib8000m3v02t0xw15l9	When does a student pay the fee for this specific real estate course?	{"Before starting Chapter 2","Halfway through the course","Only after finishing the course and passing the End-of-Course Exam","After passing the official State Exam"}	2	{"correct": "The course features a \\"don't pay until you pass\\" structure. You only pay for your certificate once you have finished the entire course, passed the End-of-Course Exam, and fully qualified for the state exam.", "incorrect": ["There is no upfront cost required to access and study the material.", "There is no midway cost required to access and study the material.", "", "The payment is for the course certificate which authorizes you to take the state exam, so it must be paid before you sit for the state test, not after."]}	3	chapter	2026-03-04 14:56:09.639	2026-03-04 15:09:26.782	\N	\N	\N	\N	/audio/1772636963348-The_course_features_.mp3	/timestamps/1772636963348-The_course_features_.timestamps.json	["/audio/1772636964511-There_is_no_upfront_.mp3", "/audio/1772636965430-There_is_no_midway_c.mp3", "", "/audio/1772636966529-The_payment_is_for_t.mp3"]	["/timestamps/1772636964511-There_is_no_upfront_.timestamps.json", "/timestamps/1772636965430-There_is_no_midway_c.timestamps.json", "", "/timestamps/1772636966529-The_payment_is_for_t.timestamps.json"]	["/audio/1772636959709-Before_starting_Chap.mp3", "/audio/1772636960205-Halfway_through_the_.mp3", "/audio/1772636961049-Only_after_finishing.mp3", "/audio/1772636961700-After_passing_the_of.mp3"]	["/timestamps/1772636959709-Before_starting_Chap.timestamps.json", "/timestamps/1772636960205-Halfway_through_the_.timestamps.json", "/timestamps/1772636961049-Only_after_finishing.timestamps.json", "/timestamps/1772636961700-After_passing_the_of.timestamps.json"]	/audio/1772636958946-When_does_a_student_.mp3	/timestamps/1772636958946-When_does_a_student_.timestamps.json
cmlttl4ya00q3r4ev26acx16q	cmlslqsgt00l1r4evfhnwe7be	An unlicensed personal assistant working for a sales associate in property management is legally permitted to perform administrative tasks, but is strictly PROHIBITED from performing which of the following actions?	{"Showing apartments to tenants","Advertising apartments for rent","Inspecting apartments","Collecting rent from tenants"}	0	{"correct": "Under Florida Real Estate Commission (FREC) guidelines, an unlicensed assistant is strictly prohibited from showing property to prospective buyers or tenants. While they may drive a prospect to a property or hand out a key, they cannot physically walk them through the property, provide access for a showing, or answer subjective questions about the property features or lease terms.", "incorrect": ["", "Unlicensed assistants are permitted to write and prepare advertising materials, provided the ads are reviewed and approved by the licensee and the supervising broker before being placed.", "Unlicensed assistants can perform administrative property management tasks such as conducting routine property inspections, taking photos for records, or meeting vendors and repairmen at the property.", "<div>FREC explicitly permits unlicensed assistants to receive, record, and deposit earnest money, security deposits, and advance rents on behalf of the brokerage.<br></div>"]}	23	chapter	2026-02-19 18:54:13.33	2026-02-19 19:59:20.29	\N	\N	\N	\N	/audio/1771531155330-Under_Florida_Real_E.mp3	/timestamps/1771531155330-Under_Florida_Real_E.timestamps.json	["", "/audio/1771531157041-Unlicensed_assistant.mp3", "/audio/1771531158778-Unlicensed_assistant.mp3", "/audio/1771531160107-FREC_explicitly_perm.mp3"]	["", "/timestamps/1771531157041-Unlicensed_assistant.timestamps.json", "/timestamps/1771531158778-Unlicensed_assistant.timestamps.json", "/timestamps/1771531160107-FREC_explicitly_perm.timestamps.json"]	["/audio/1771531150360-Showing_apartments_t.mp3", "/audio/1771531151113-Advertising_apartmen.mp3", "/audio/1771531151834-Inspecting_apartment.mp3", "/audio/1771531152455-Collecting_rent_from.mp3"]	["/timestamps/1771531150360-Showing_apartments_t.timestamps.json", "/timestamps/1771531151113-Advertising_apartmen.timestamps.json", "/timestamps/1771531151834-Inspecting_apartment.timestamps.json", "/timestamps/1771531152455-Collecting_rent_from.timestamps.json"]	/audio/1771531149628-An_unlicensed_person.mp3	/timestamps/1771531149628-An_unlicensed_person.timestamps.json
cmmqfnzpr002y4be71f99io5t	cmmqbpz7v00044be7x0za79d7	Which group is NOT protected under the Federal Fair Housing Act?	{"People with HIV/AIDS","Pregnant women","People over the age of 65",Christians}	2	{"correct": "Age is not a protected class under the Federal Fair Housing Act. Landlords can generally refuse to rent to someone based on age (unless it violates state/local law).", "incorrect": ["Protected under Handicap status.", "Protected under Familial Status.", "", "Protected under Religion."]}	9	chapter	2026-03-14 14:40:55.695	2026-03-14 23:12:40.68	\N	\N	\N	\N	/audio/1773529957909-Age_is_not_a_protect.mp3	/timestamps/1773529957909-Age_is_not_a_protect.timestamps.json	["/audio/1773529958797-Protected_under_Hand.mp3", "/audio/1773529959721-Protected_under_Fami.mp3", "", "/audio/1773529960521-Protected_under_Reli.mp3"]	["/timestamps/1773529958797-Protected_under_Hand.timestamps.json", "/timestamps/1773529959721-Protected_under_Fami.timestamps.json", "", "/timestamps/1773529960521-Protected_under_Reli.timestamps.json"]	["/audio/1773529953672-People_with_HIV_AIDS.mp3", "/audio/1773529954470-Pregnant_women.mp3", "/audio/1773529955468-People_over_the_age_.mp3", "/audio/1773529956091-Christians.mp3"]	["/timestamps/1773529953672-People_with_HIV_AIDS.timestamps.json", "/timestamps/1773529954470-Pregnant_women.timestamps.json", "/timestamps/1773529955468-People_over_the_age_.timestamps.json", "/timestamps/1773529956091-Christians.timestamps.json"]	/audio/1773529952955-Which_group_is_NOT_p.mp3	/timestamps/1773529952955-Which_group_is_NOT_p.timestamps.json
cmltu0kb400q7r4ev7qefj1uq	cmlslqsgt00l1r4evfhnwe7be	A sales associate receives a binder deposit check from a buyer. How much time does the associate have to deliver this check to their employing broker to comply with Florida law?	{"3 business days","7 days","By the end of the next business day","Within 24 hours of receipt"}	2	{"correct": "Sales associate, must deliver the check to their broker immediately. This means by the end of the next business day.", "incorrect": ["3 business days is the deadline for the Broker to deposit the funds into the bank. Do not confuse the associate's deadline (1 day) with the broker's deadline (3 days).", "&nbsp;7 days is far too long and puts the funds at risk.", "", "<div>While \\"next business day\\" is often close to 24 hours, the legal standard is not \\"24 hours.\\" For example, if you receive a check on Friday, \\"24 hours\\" implies Saturday, but \\"next business day\\" gives you until Monday.</div>"]}	25	chapter	2026-02-19 19:06:13.072	2026-02-19 19:59:41.702	\N	\N	\N	\N	/audio/1771531177114-Sales_associate__mus.mp3	/timestamps/1771531177114-Sales_associate__mus.timestamps.json	["/audio/1771531178929-3_business_days_is_t.mp3", "/audio/1771531179778-7_days_is_far_too_lo.mp3", "", "/audio/1771531181534-While__next_business.mp3"]	["/timestamps/1771531178929-3_business_days_is_t.timestamps.json", "/timestamps/1771531179778-7_days_is_far_too_lo.timestamps.json", "", "/timestamps/1771531181534-While__next_business.timestamps.json"]	["/audio/1771531173535-3_business_days.mp3", "/audio/1771531174237-7_days.mp3", "/audio/1771531175024-By_the_end_of_the_ne.mp3", "/audio/1771531175652-Within_24_hours_of_r.mp3"]	["/timestamps/1771531173535-3_business_days.timestamps.json", "/timestamps/1771531174237-7_days.timestamps.json", "/timestamps/1771531175024-By_the_end_of_the_ne.timestamps.json", "/timestamps/1771531175652-Within_24_hours_of_r.timestamps.json"]	/audio/1771531172954-A_sales_associate_re.mp3	/timestamps/1771531172954-A_sales_associate_re.timestamps.json
cmlttx5gy00q5r4ev8pe6wlti	cmlslqsgt00l1r4evfhnwe7be	Julie Baker is a licensed real estate sales associate. Which of the following names is she legally permitted to use to register and hold her license?	{"Julie Baker Sells Florida","Julie Baker Brokerage","Julie Baker, LLC","Julie Baker and Partners"}	2	{"correct": "A sales associate is allowed to form a specific legal entity for tax purposes, such as a Limited Liability Company (LLC) or a Professional Association (PA). However, the entity name must be their legal name (e.g., \\"Julie Baker, LLC”).", "incorrect": ["\\"Julie Baker Sells Florida\\" is a Trade Name (or fictitious name). Sales associates are strictly prohibited from using trade names.", "Using the word \\"Brokerage\\" implies she is the broker/owner of the company, which misleads the public about her status as an associate.", "", "<div>\\"And Partners\\" implies a partnership, which is a specific business entity that a single sales associate cannot form for their license. It also suggests a level of authority/ownership she does not possess.</div>"]}	24	chapter	2026-02-19 19:03:33.811	2026-02-19 19:59:31.396	\N	\N	\N	\N	/audio/1771531166992-A_sales_associate_is.mp3	/timestamps/1771531166992-A_sales_associate_is.timestamps.json	["/audio/1771531168426-_Julie_Baker_Sells_F.mp3", "/audio/1771531169657-Using_the_word__Brok.mp3", "", "/audio/1771531171232-_And_Partners__impli.mp3"]	["/timestamps/1771531168426-_Julie_Baker_Sells_F.timestamps.json", "/timestamps/1771531169657-Using_the_word__Brok.timestamps.json", "", "/timestamps/1771531171232-_And_Partners__impli.timestamps.json"]	["/audio/1771531162452-Julie_Baker_Sells_Fl.mp3", "/audio/1771531163190-Julie_Baker_Brokerag.mp3", "/audio/1771531163932-Julie_Baker__LLC.mp3", "/audio/1771531164674-Julie_Baker_and_Part.mp3"]	["/timestamps/1771531162452-Julie_Baker_Sells_Fl.timestamps.json", "/timestamps/1771531163190-Julie_Baker_Brokerag.timestamps.json", "/timestamps/1771531163932-Julie_Baker__LLC.timestamps.json", "/timestamps/1771531164674-Julie_Baker_and_Part.timestamps.json"]	/audio/1771531161788-Julie_Baker_is_a_lic.mp3	/timestamps/1771531161788-Julie_Baker_is_a_lic.timestamps.json
cmltu3f5600q9r4ev7v3jpem7	cmlslqsgt00l1r4evfhnwe7be	Which statement is TRUE regarding the Florida Commercial Real Estate Sales Commission Lien Act?	{"The lien attaches directly to the commercial real estate, acting as a cloud on the title.","The Act allows brokers to place a lien exclusively on the owner's net proceeds from the sale of commercial property","The broker can use this Act to attach a lien to the net proceeds from the sale of both residential and commercial properties","The lien attaches to the buyer's earnest money deposit held in escrow"}	1	{"correct": "The Act is strictly limited to commercial properties. Under this specific Act, a broker's lien for an earned commission attaches only to the owner's net proceeds (the cash the seller walks away with at closing), not the actual real estate.", "incorrect": ["The Act explicitly states that the lien does NOT attach to the real property itself. It is a lien on the money (personal property), so it does not encumber the actual building or land being sold.", "", "As the name implies, this Act is for commercial properties only. Florida law does not provide an automatic statutory lien on net proceeds for residential real estate sales.", "<div>The lien attaches to the seller's final net proceeds from the disposition of the property, not the buyer's upfront earnest money deposit.</div>"]}	26	chapter	2026-02-19 19:08:26.346	2026-02-19 19:59:54.146	\N	\N	\N	\N	/audio/1771531189451-The_Act_is_strictly_.mp3	/timestamps/1771531189451-The_Act_is_strictly_.timestamps.json	["/audio/1771531191131-The_Act_explicitly_s.mp3", "", "/audio/1771531192680-As_the_name_implies_.mp3", "/audio/1771531193968-The_lien_attaches_to.mp3"]	["/timestamps/1771531191131-The_Act_explicitly_s.timestamps.json", "", "/timestamps/1771531192680-As_the_name_implies_.timestamps.json", "/timestamps/1771531193968-The_lien_attaches_to.timestamps.json"]	["/audio/1771531183709-The_lien_attaches_di.mp3", "/audio/1771531185004-The_Act_allows_broke.mp3", "/audio/1771531186271-The_broker_can_use_t.mp3", "/audio/1771531187299-The_lien_attaches_to.mp3"]	["/timestamps/1771531183709-The_lien_attaches_di.timestamps.json", "/timestamps/1771531185004-The_Act_allows_broke.timestamps.json", "/timestamps/1771531186271-The_broker_can_use_t.timestamps.json", "/timestamps/1771531187299-The_lien_attaches_to.timestamps.json"]	/audio/1771531182809-Which_statement_is_T.mp3	/timestamps/1771531182809-Which_statement_is_T.timestamps.json
cmltu5x1700qbr4ev688rs48f	cmlslqsgt00l1r4evfhnwe7be	A broker is preparing to open Palm Tree Realty and is placing an order to have an entrance sign made. Which wording does NOT need to be included on the sign?	{"Office Address","The broker’s legal name","Licensed Real Estate Broker","Palm Tree Realty"}	0	{"correct": "Correct (A): Under Florida law (Statute 475.22), the office address is not a requirement to be printed on the broker's entrance sign.", "incorrect": ["", "The name of the broker (specifically, at least one of the qualifying brokers if it's a partnership or corporation) is a mandatory requirement for the sign.", "The words \\"Licensed Real Estate Broker\\" or the abbreviation \\"Lic. Real Estate Broker\\" must appear on the sign by law.", "<div>If the brokerage operates under a trade name (like Palm Tree Realty), that trade name must be included on the sign.</div>"]}	27	chapter	2026-02-19 19:10:22.842	2026-02-19 20:00:04.189	\N	\N	\N	\N	/audio/1771531199953-Correct__A___Under_F.mp3	/timestamps/1771531199953-Correct__A___Under_F.timestamps.json	["", "/audio/1771531201532-The_name_of_the_brok.mp3", "/audio/1771531202767-The_words__Licensed_.mp3", "/audio/1771531203997-If_the_brokerage_ope.mp3"]	["", "/timestamps/1771531201532-The_name_of_the_brok.timestamps.json", "/timestamps/1771531202767-The_words__Licensed_.timestamps.json", "/timestamps/1771531203997-If_the_brokerage_ope.timestamps.json"]	["/audio/1771531196252-Office_Address.mp3", "/audio/1771531196833-The_broker_s_legal_n.mp3", "/audio/1771531197560-Licensed_Real_Estate.mp3", "/audio/1771531198325-Palm_Tree_Realty.mp3"]	["/timestamps/1771531196252-Office_Address.timestamps.json", "/timestamps/1771531196833-The_broker_s_legal_n.timestamps.json", "/timestamps/1771531197560-Licensed_Real_Estate.timestamps.json", "/timestamps/1771531198325-Palm_Tree_Realty.timestamps.json"]	/audio/1771531195619-A_broker_is_preparin.mp3	/timestamps/1771531195619-A_broker_is_preparin.timestamps.json
cmmc607s000273v02nglj635i	cmmbeuib8000m3v02t0xw15l9	How many chapters make up the structure of this course?	{"10 chapters","15 chapters","20 chapters","63 chapters"}	2	{"correct": "The course is strategically designed with 20 power-packed chapters, each strengthened by interactive quizzes that help cement the material into your memory — not just for now, but for exam day. You’re already close to finishing Chapter 1 — great start. Yes, the chapters ahead will become more challenging… but that’s exactly where our game-changing quiz system shines. With instant feedback, smart explanations, and repetition that actually works, you won’t just study — you’ll master the material and build the confidence you need to walk into both exams ready to pass.", "incorrect": ["The material is divided into 20 chapters, not 10.", "The material is divided into 20 chapters, not 15.", "", "While the course takes 63 hours to complete, it is broken down into 20 chapters, not 63."]}	4	chapter	2026-03-04 15:01:43.391	2026-03-04 15:09:35.496	\N	\N	\N	\N	/audio/1772636972376-The_course_is_strate.mp3	/timestamps/1772636972376-The_course_is_strate.timestamps.json	["/audio/1772636973244-The_material_is_divi.mp3", "/audio/1772636974114-The_material_is_divi.mp3", "", "/audio/1772636975254-While_the_course_tak.mp3"]	["/timestamps/1772636973244-The_material_is_divi.timestamps.json", "/timestamps/1772636974114-The_material_is_divi.timestamps.json", "", "/timestamps/1772636975254-While_the_course_tak.timestamps.json"]	["/audio/1772636968216-10_chapters.mp3", "/audio/1772636968747-15_chapters.mp3", "/audio/1772636969268-20_chapters.mp3", "/audio/1772636969847-63_chapters.mp3"]	["/timestamps/1772636968216-10_chapters.timestamps.json", "/timestamps/1772636968747-15_chapters.timestamps.json", "/timestamps/1772636969268-20_chapters.timestamps.json", "/timestamps/1772636969847-63_chapters.timestamps.json"]	/audio/1772636967591-How_many_chapters_ma.mp3	/timestamps/1772636967591-How_many_chapters_ma.timestamps.json
cmltu9u0i00qdr4evykc8pf40	cmlslqsgt00l1r4evfhnwe7be	An attorney and a real estate broker form a joint venture to sell real estate for compensation. Which statement is TRUE regarding this arrangement?	{"They both must hold a broker's license","Only the broker must hold the broker's license","A license is not required for Joint Ventures","Because the attorney can practice real estate, the broker doesn't need a license"}	0	{"correct": "If a joint venture is formed to perform real estate brokerage services for the public, all participants who are acting as principals in that venture must hold an active real estate broker's license. While attorneys have some exemptions in real estate law (like drafting contracts for a client), they are not exempt from licensing if they are actively brokering real estate and earning a commission. Therefore, the attorney must also get a broker's license to legally participate in this sales venture.", "incorrect": ["", "You cannot have an unlicensed partner (the attorney, in this specific real estate context) acting as a principal in a joint venture that is providing real estate brokerage services. Both must be licensed brokers.", "While a joint venture is a temporary business arrangement and cannot be permanently registered as a brokerage entity with the DBPR, the individuals conducting the real estate services within it absolutely must hold active broker licenses.", "<div>An attorney's law license does not grant them a blanket right to act as a real estate broker for a commission. Furthermore, even if it did, it would not negate the requirement for the actual broker to be licensed.</div>"]}	28	chapter	2026-02-19 19:13:25.553	2026-02-19 20:00:17.392	\N	\N	\N	\N	/audio/1771531212197-If_a_joint_venture_i.mp3	/timestamps/1771531212197-If_a_joint_venture_i.timestamps.json	["", "/audio/1771531213971-You_cannot_have_an_u.mp3", "/audio/1771531215689-While_a_joint_ventur.mp3", "/audio/1771531217231-An_attorney_s_law_li.mp3"]	["", "/timestamps/1771531213971-You_cannot_have_an_u.timestamps.json", "/timestamps/1771531215689-While_a_joint_ventur.timestamps.json", "/timestamps/1771531217231-An_attorney_s_law_li.timestamps.json"]	["/audio/1771531206316-They_both_must_hold_.mp3", "/audio/1771531206978-Only_the_broker_must.mp3", "/audio/1771531207855-A_license_is_not_req.mp3", "/audio/1771531208822-Because_the_attorney.mp3"]	["/timestamps/1771531206316-They_both_must_hold_.timestamps.json", "/timestamps/1771531206978-Only_the_broker_must.timestamps.json", "/timestamps/1771531207855-A_license_is_not_req.timestamps.json", "/timestamps/1771531208822-Because_the_attorney.timestamps.json"]	/audio/1771531205648-An_attorney_and_a_re.mp3	/timestamps/1771531205648-An_attorney_and_a_re.timestamps.json
cmmqfscm000304be7q2wvnqu2	cmmqbpz7v00044be7x0za79d7	Which activity is specifically prohibited under the Fair Housing Act?	{"Evicting a tenant for destroying property","Refusing to rent to a smoker","Quoting different lease terms to an applicant based on their national origin","Charging a higher deposit for a tenant with a waterbed"}	2	{"correct": "Quoting different terms (discriminatory terms) based on a protected class (National Origin) is illegal.", "incorrect": ["Eviction for cause (damage) is legal.", "Smokers are not a protected class.", "", "Waterbed owners are not a protected class."]}	10	chapter	2026-03-14 14:44:19.032	2026-03-14 23:12:49.71	\N	\N	\N	\N	/audio/1773529966977-Quoting_different_te.mp3	/timestamps/1773529966977-Quoting_different_te.timestamps.json	["/audio/1773529967926-Eviction_for_cause__.mp3", "/audio/1773529968679-Smokers_are_not_a_pr.mp3", "", "/audio/1773529969463-Waterbed_owners_are_.mp3"]	["/timestamps/1773529967926-Eviction_for_cause__.timestamps.json", "/timestamps/1773529968679-Smokers_are_not_a_pr.timestamps.json", "", "/timestamps/1773529969463-Waterbed_owners_are_.timestamps.json"]	["/audio/1773529962563-Evicting_a_tenant_fo.mp3", "/audio/1773529963270-Refusing_to_rent_to_.mp3", "/audio/1773529964428-Quoting_different_le.mp3", "/audio/1773529965368-Charging_a_higher_de.mp3"]	["/timestamps/1773529962563-Evicting_a_tenant_fo.timestamps.json", "/timestamps/1773529963270-Refusing_to_rent_to_.timestamps.json", "/timestamps/1773529964428-Quoting_different_le.timestamps.json", "/timestamps/1773529965368-Charging_a_higher_de.timestamps.json"]	/audio/1773529961807-Which_activity_is_sp.mp3	/timestamps/1773529961807-Which_activity_is_sp.timestamps.json
cmltucx4600qfr4ev2xm5tpqf	cmlslqsgt00l1r4evfhnwe7be	The sales commission rates for properties sold in Florida are based on:	{"Rules of the Florida Real Estate Commission","MLS association","An agreement between broker and seller or buyer","Local Realtor association"}	2	{"correct": "Real estate commission rates are always freely negotiable between the broker and their principal (the seller or the buyer). The agreed-upon rate or fee is documented in the employment contract, such as a listing agreement or a buyer broker agreement.", "incorrect": ["The Florida Real Estate Commission (FREC) does not set, suggest, dictate, or regulate commission rates in any way.", "It is a strict violation of federal law (specifically the Sherman Antitrust Act) for any Multiple Listing Service (MLS), local Realtor association, or group of competing brokers to collude, fix, set, or establish standard or \\"routine\\" commission rates. Rates must always remain completely negotiable to preserve fair market competition.", "", "<div>It is a strict violation of federal law (specifically the Sherman Antitrust Act) for any Multiple Listing Service (MLS), local Realtor association, or group of competing brokers to collude, fix, set, or establish standard or \\"routine\\" commission rates. Rates must always remain completely negotiable to preserve fair market competition.<br></div>"]}	29	chapter	2026-02-19 19:15:49.542	2026-02-19 20:00:31.489	\N	\N	\N	\N	/audio/1771531224256-Real_estate_commissi.mp3	/timestamps/1771531224256-Real_estate_commissi.timestamps.json	["/audio/1771531225833-The_Florida_Real_Est.mp3", "/audio/1771531228680-It_is_a_strict_viola.mp3", "", "/audio/1771531231296-It_is_a_strict_viola.mp3"]	["/timestamps/1771531225833-The_Florida_Real_Est.timestamps.json", "/timestamps/1771531228680-It_is_a_strict_viola.timestamps.json", "", "/timestamps/1771531231296-It_is_a_strict_viola.timestamps.json"]	["/audio/1771531219859-Rules_of_the_Florida.mp3", "/audio/1771531220544-MLS_association.mp3", "/audio/1771531221405-An_agreement_between.mp3", "/audio/1771531222279-Local_Realtor_associ.mp3"]	["/timestamps/1771531219859-Rules_of_the_Florida.timestamps.json", "/timestamps/1771531220544-MLS_association.timestamps.json", "/timestamps/1771531221405-An_agreement_between.timestamps.json", "/timestamps/1771531222279-Local_Realtor_associ.timestamps.json"]	/audio/1771531219149-The_sales_commission.mp3	/timestamps/1771531219149-The_sales_commission.timestamps.json
cmltug9oz00qhr4ev6a2hict0	cmlslqsgt00l1r4evfhnwe7be	&nbsp;If the only active broker of a real estate brokerage dies or resigns, which statement is TRUE regarding the brokerage's business operations during the 14-day period allowed to fill the vacancy?	{"The brokerage must completely shut down and cannot manage any existing business until a new broker is appointed","The associates may continue to take on new listings and sign new buyer agreements as long as a broker is appointed within 14 days","The brokerage can continue to manage existing business currently in progress, but no new brokerage business may be performed","A temporary broker must be appointed within 24 hours to manage any existing or new business"}	2	{"correct": "During the 14-day window to fill a sole broker vacancy, the law explicitly prohibits the brokerage or its licensees from taking on any new brokerage business. However, business that is already in progress, such as managing existing listings or pending contracts, may continue to be managed to protect the current clients.", "incorrect": ["The brokerage is not forced to completely abandon its current clients; existing business can continue to be serviced during this 14-day grace period.", "Associates are strictly prohibited from performing any new brokerage business (like signing new listings or buyer broker agreements) until a new temporary or permanent broker is officially registered with the DBPR.", "", "<div>The brokerage has a full 14 calendar days (not 24 hours) to officially appoint either a permanent or temporary broker to fill the vacancy.</div>"]}	30	chapter	2026-02-19 19:18:25.81	2026-02-19 20:00:45.692	\N	\N	\N	\N	/audio/1771531240736-During_the_14_day_wi.mp3	/timestamps/1771531240736-During_the_14_day_wi.timestamps.json	["/audio/1771531242362-The_brokerage_is_not.mp3", "/audio/1771531244145-Associates_are_stric.mp3", "", "/audio/1771531245477-The_brokerage_has_a_.mp3"]	["/timestamps/1771531242362-The_brokerage_is_not.timestamps.json", "/timestamps/1771531244145-Associates_are_stric.timestamps.json", "", "/timestamps/1771531245477-The_brokerage_has_a_.timestamps.json"]	["/audio/1771531234498-The_brokerage_must_c.mp3", "/audio/1771531235829-The_associates_may_c.mp3", "/audio/1771531237097-The_brokerage_can_co.mp3", "/audio/1771531238237-A_temporary_broker_m.mp3"]	["/timestamps/1771531234498-The_brokerage_must_c.timestamps.json", "/timestamps/1771531235829-The_associates_may_c.timestamps.json", "/timestamps/1771531237097-The_brokerage_can_co.timestamps.json", "/timestamps/1771531238237-A_temporary_broker_m.timestamps.json"]	/audio/1771531233391-If_the_only_active_b.mp3	/timestamps/1771531233391-If_the_only_active_b.timestamps.json
cmltuooxy00qnr4evvy7i93in	cmlslqsgt00l1r4evfhnwe7be	Two real estate brokers decide to combine their resources and expertise solely to market and sell a specific shopping mall in Miami. They do not intend to merge their brokerages permanently, and their agreement applies only to this single transaction. What type of business arrangement have they formed?	{"A general partnership","An ostensible partnership","A joint venture","A business trust"}	2	{"correct": "A joint venture is a temporary business arrangement formed by two or more parties for a single, specific project or transaction (like selling one specific shopping mall) without permanently merging their businesses. When composed of separate, licensed real estate brokers, the joint venture itself does not need to be registered with the DBPR as a new brokerage.", "incorrect": ["A general partnership is typically formed to conduct an ongoing business together, not just a single, isolated, temporary project.", "An ostensible (or quasi) partnership is a prohibited, fake partnership where parties act like partners to deceive the public, not a legitimate agreement to co-market a single property.", "", "<div>A business trust is a different entity type involving trustees managing investments, and it cannot be registered as a real estate brokerage in Florida.</div>"]}	33	chapter	2026-02-19 19:24:58.821	2026-02-19 20:01:22.43	\N	\N	\N	\N	/audio/1771531278073-A_joint_venture_is_a.mp3	/timestamps/1771531278073-A_joint_venture_is_a.timestamps.json	["/audio/1771531279603-A_general_partnershi.mp3", "/audio/1771531281113-An_ostensible__or_qu.mp3", "", "/audio/1771531282257-A_business_trust_is_.mp3"]	["/timestamps/1771531279603-A_general_partnershi.timestamps.json", "/timestamps/1771531281113-An_ostensible__or_qu.timestamps.json", "", "/timestamps/1771531282257-A_business_trust_is_.timestamps.json"]	["/audio/1771531273748-A_general_partnershi.mp3", "/audio/1771531274454-An_ostensible_partne.mp3", "/audio/1771531274991-A_joint_venture.mp3", "/audio/1771531275518-A_business_trust.mp3"]	["/timestamps/1771531273748-A_general_partnershi.timestamps.json", "/timestamps/1771531274454-An_ostensible_partne.timestamps.json", "/timestamps/1771531274991-A_joint_venture.timestamps.json", "/timestamps/1771531275518-A_business_trust.timestamps.json"]	/audio/1771531273191-Two_real_estate_brok.mp3	/timestamps/1771531273191-Two_real_estate_brok.timestamps.json
cmmqfusge00324be7qfz25au7	cmmqbpz7v00044be7x0za79d7	The "Mrs. Murphy" exemption applies to owner-occupied rentals of how many units?	{"10 or fewer","5 or fewer","4 or fewer","Single-family homes only"}	2	{"correct": "&nbsp;The exemption applies to multifamily dwellings of four or fewer units, provided the owner lives in one of them as their permanent residence.", "incorrect": ["Any building with 5+ units is always covered.", "Any building with 5+ units is always covered.", "", "The exemption specifically applies to small multifamily units (duplex/triplex/quadplex)."]}	11	chapter	2026-03-14 14:46:12.878	2026-03-14 23:12:59.226	\N	\N	\N	\N	/audio/1773529975435-The_exemption_applie.mp3	/timestamps/1773529975435-The_exemption_applie.timestamps.json	["/audio/1773529976637-Any_building_with_5_.mp3", "/audio/1773529977829-Any_building_with_5_.mp3", "", "/audio/1773529978966-The_exemption_specif.mp3"]	["/timestamps/1773529976637-Any_building_with_5_.timestamps.json", "/timestamps/1773529977829-Any_building_with_5_.timestamps.json", "", "/timestamps/1773529978966-The_exemption_specif.timestamps.json"]	["/audio/1773529971558-10_or_fewer.mp3", "/audio/1773529972170-5_or_fewer.mp3", "/audio/1773529973038-4_or_fewer.mp3", "/audio/1773529973800-Single_family_homes_.mp3"]	["/timestamps/1773529971558-10_or_fewer.timestamps.json", "/timestamps/1773529972170-5_or_fewer.timestamps.json", "/timestamps/1773529973038-4_or_fewer.timestamps.json", "/timestamps/1773529973800-Single_family_homes_.timestamps.json"]	/audio/1773529970872-The__Mrs__Murphy__ex.mp3	/timestamps/1773529970872-The__Mrs__Murphy__ex.timestamps.json
cmltuj46w00qjr4ev86mk1bq9	cmlslqsgt00l1r4evfhnwe7be	Who do real estate listings and commissions generated from those listings belong to in Florida?	{"The sales associate who got the listing","Jointly owned by the sales associate who got the listing and their employer","The sales associate's employer","Association of Realtors"}	2	{"correct": "All listings, contracts, and commissions legally belong to the sales associate's employer (the broker or the brokerage entity). The sales associate acts as a general agent of the broker, meaning they are authorized to secure listings on the broker's behalf, but the brokerage is the actual party entering into the contract with the seller.", "incorrect": ["While the sales associate is the one who procured the client and did the legwork, they are doing so strictly as a representative of the broker. If the sales associate leaves to work for a new brokerage, the listing stays with the original broker unless that broker explicitly agrees to release it.", "There is no joint ownership. The employing broker is the sole legal owner of the listing agreement.", "", "<div>The Association of Realtors is a trade organization. While they provide the standard forms and operate the local Multiple Listing Service (MLS), they do not own the actual employment contracts established between property sellers and brokerages.</div>"]}	31	chapter	2026-02-19 19:20:38.648	2026-02-19 20:00:57.846	\N	\N	\N	\N	/audio/1771531252378-All_listings__contra.mp3	/timestamps/1771531252378-All_listings__contra.timestamps.json	["/audio/1771531254753-While_the_sales_asso.mp3", "/audio/1771531255813-There_is_no_joint_ow.mp3", "", "/audio/1771531257657-The_Association_of_R.mp3"]	["/timestamps/1771531254753-While_the_sales_asso.timestamps.json", "/timestamps/1771531255813-There_is_no_joint_ow.timestamps.json", "", "/timestamps/1771531257657-The_Association_of_R.timestamps.json"]	["/audio/1771531248002-The_sales_associate_.mp3", "/audio/1771531248888-Jointly_owned_by_the.mp3", "/audio/1771531249471-The_sales_associate_.mp3", "/audio/1771531250041-Association_of_Realt.mp3"]	["/timestamps/1771531248002-The_sales_associate_.timestamps.json", "/timestamps/1771531248888-Jointly_owned_by_the.timestamps.json", "/timestamps/1771531249471-The_sales_associate_.timestamps.json", "/timestamps/1771531250041-Association_of_Realt.timestamps.json"]	/audio/1771531247351-Who_do_real_estate_l.mp3	/timestamps/1771531247351-Who_do_real_estate_l.timestamps.json
cmmbfg7sx000y3v02h0s71y2l	cmmbeuib8000m3v02t0xw15l9	In addition to attending the required pre-licensing education hours, what must a student achieve to successfully complete the course requirement?	{"Pass a DBPR-administered interview","Complete a 30-day apprenticeship with a broker","Pass the course final exam","Submit three letters of recommendation"}	2	{"correct": "Student must pass course's final exam before being cleared to take the state exam.", "incorrect": ["The DBPR does not conduct personal interviews for standard licensing.", "<div>Apprenticeships are not a required part of the Florida pre-licensing process.<br></div>", "", "Letters of recommendation are not required for a standard real estate application."]}	4	chapter	2026-03-04 02:38:20.288	2026-03-04 15:09:43.675	\N	\N	\N	\N	/audio/1772636980586-Student_must_pass_co.mp3	/timestamps/1772636980586-Student_must_pass_co.timestamps.json	["/audio/1772636981650-The_DBPR_does_not_co.mp3", "/audio/1772636982597-Apprenticeships_are_.mp3", "", "/audio/1772636983477-Letters_of_recommend.mp3"]	["/timestamps/1772636981650-The_DBPR_does_not_co.timestamps.json", "/timestamps/1772636982597-Apprenticeships_are_.timestamps.json", "", "/timestamps/1772636983477-Letters_of_recommend.timestamps.json"]	["/audio/1772636977491-Pass_a_DBPR_administ.mp3", "/audio/1772636978332-Complete_a_30_day_ap.mp3", "/audio/1772636978971-Pass_the_course_fina.mp3", "/audio/1772636979652-Submit_three_letters.mp3"]	["/timestamps/1772636977491-Pass_a_DBPR_administ.timestamps.json", "/timestamps/1772636978332-Complete_a_30_day_ap.timestamps.json", "/timestamps/1772636978971-Pass_the_course_fina.timestamps.json", "/timestamps/1772636979652-Submit_three_letters.timestamps.json"]	/audio/1772636976714-In_addition_to_atten.mp3	/timestamps/1772636976714-In_addition_to_atten.timestamps.json
cmltum8be00qlr4evg303p6ed	cmlslqsgt00l1r4evfhnwe7be	Which statement is TRUE regarding a real estate licensee receiving a fee for referring a buyer to a title company?	{"The licensee may receive a fee if they disclose it to the buyer in advance","The licensee is strictly prohibited from receiving a referral fee, regardless of whether it is disclosed to the buyer","The licensee may receive a fee only if the title company is affiliated with their brokerage","The licensee may receive a fee if the broker approves the transaction and signs the disclosure"}	1	{"correct": "Under the federal Real Estate Settlement Procedures Act (RESPA), it is strictly prohibited for a real estate licensee to receive a kickback or referral fee for directing a buyer to a specific settlement service provider, such as a title company. Disclosing the fee to the buyer in advance does not make the illegal kickback permissible.", "incorrect": ["Disclosure does not cure a RESPA violation. A kickback for a settlement service referral is illegal whether it is hidden or disclosed.", "", "Even within a legal Affiliated Business Arrangement (AfBA) where the broker owns a piece of the title company, the licensee cannot receive a direct referral fee or kickback simply for sending the business. They can only receive a legitimate return on their ownership interest.", "<div>A broker cannot authorize an illegal act. Kickbacks for settlement services violate federal law, making broker approval irrelevant.</div>"]}	32	chapter	2026-02-19 19:23:03.962	2026-02-19 20:01:10.884	\N	\N	\N	\N	/audio/1771531265807-Under_the_federal_Re.mp3	/timestamps/1771531265807-Under_the_federal_Re.timestamps.json	["/audio/1771531267275-Disclosure_does_not_.mp3", "", "/audio/1771531269289-Even_within_a_legal_.mp3", "/audio/1771531270734-A_broker_cannot_auth.mp3"]	["/timestamps/1771531267275-Disclosure_does_not_.timestamps.json", "", "/timestamps/1771531269289-Even_within_a_legal_.timestamps.json", "/timestamps/1771531270734-A_broker_cannot_auth.timestamps.json"]	["/audio/1771531260048-The_licensee_may_rec.mp3", "/audio/1771531261289-The_licensee_is_stri.mp3", "/audio/1771531262202-The_licensee_may_rec.mp3", "/audio/1771531263286-The_licensee_may_rec.mp3"]	["/timestamps/1771531260048-The_licensee_may_rec.timestamps.json", "/timestamps/1771531261289-The_licensee_is_stri.timestamps.json", "/timestamps/1771531262202-The_licensee_may_rec.timestamps.json", "/timestamps/1771531263286-The_licensee_may_rec.timestamps.json"]	/audio/1771531259224-Which_statement_is_T.mp3	/timestamps/1771531259224-Which_statement_is_T.timestamps.json
cmmc653lk002b3v02se5afdvh	cmmbeuib8000m3v02t0xw15l9	What is the cost of the certificate once the End-of-Course Exam is passed?	{$99,$149,$199,$250}	2	{"correct": "Once you pass the End-of-Course Exam and officially qualify to take the Florida State Exam, you simply pay $199 to receive your certificate.", "incorrect": ["This amount does not reflect the stated $199 fee for the completion certificate.", "This amount does not reflect the stated $199 fee for the completion certificate.", "", "This amount does not reflect the stated $199 fee for the completion certificate."]}	6	chapter	2026-03-04 15:05:31.256	2026-03-04 15:09:52.378	\N	\N	\N	\N	/audio/1772636988803-Once_you_pass_the_En.mp3	/timestamps/1772636988803-Once_you_pass_the_En.timestamps.json	["/audio/1772636990115-This_amount_does_not.mp3", "/audio/1772636991111-This_amount_does_not.mp3", "", "/audio/1772636992135-This_amount_does_not.mp3"]	["/timestamps/1772636990115-This_amount_does_not.timestamps.json", "/timestamps/1772636991111-This_amount_does_not.timestamps.json", "", "/timestamps/1772636992135-This_amount_does_not.timestamps.json"]	["/audio/1772636985352-_99.mp3", "/audio/1772636986054-_149.mp3", "/audio/1772636986647-_199.mp3", "/audio/1772636987198-_250.mp3"]	["/timestamps/1772636985352-_99.timestamps.json", "/timestamps/1772636986054-_149.timestamps.json", "/timestamps/1772636986647-_199.timestamps.json", "/timestamps/1772636987198-_250.timestamps.json"]	/audio/1772636984565-What_is_the_cost_of_.mp3	/timestamps/1772636984565-What_is_the_cost_of_.timestamps.json
cmmc68x0p002d3v02m2nel6f5	cmmbeuib8000m3v02t0xw15l9	Why does the program strongly recommend heading straight to the testing center after passing the End-of-Course Exam?	{"Because the certificate expires within 48 hours","Because testing centers charge late fees if you delay","Because momentum matters and knowledge fades","Because FREC legally requires you to test within one week"}	2	{"correct": "The program advises taking the state exam immediately because testing while the material is fresh yields the best results.", "incorrect": ["The completion certificate is valid for up to two years, not 48 hours.", "Testing centers do not charge late fees for waiting to schedule your initial exam.", "", "There is no FREC rule requiring you to test within a week of finishing your course; it is purely a strategic recommendation for success."]}	7	chapter	2026-03-04 15:08:29.352	2026-03-04 15:10:01.359	\N	\N	\N	\N	/audio/1772636998143-The_program_advises_.mp3	/timestamps/1772636998143-The_program_advises_.timestamps.json	["/audio/1772636999065-The_completion_certi.mp3", "/audio/1772636999899-Testing_centers_do_n.mp3", "", "/audio/1772637001207-There_is_no_FREC_rul.mp3"]	["/timestamps/1772636999065-The_completion_certi.timestamps.json", "/timestamps/1772636999899-Testing_centers_do_n.timestamps.json", "", "/timestamps/1772637001207-There_is_no_FREC_rul.timestamps.json"]	["/audio/1772636994236-Because_the_certific.mp3", "/audio/1772636994986-Because_testing_cent.mp3", "/audio/1772636995816-Because_momentum_mat.mp3", "/audio/1772636996649-Because_FREC_legally.mp3"]	["/timestamps/1772636994236-Because_the_certific.timestamps.json", "/timestamps/1772636994986-Because_testing_cent.timestamps.json", "/timestamps/1772636995816-Because_momentum_mat.timestamps.json", "/timestamps/1772636996649-Because_FREC_legally.timestamps.json"]	/audio/1772636993454-Why_does_the_program.mp3	/timestamps/1772636993454-Why_does_the_program.timestamps.json
cmlturzr800qpr4evz2sexmns	cmlslqsgt00l1r4evfhnwe7be	When a real estate contract specifies that a Title Company (rather than the Broker) will hold the escrow deposit, which information regarding that Title Company must be included in the purchase and sale agreement?	{"Address, telephone number, and name of the title company ","Name, phone and email address of the Attorney for the Title company","The name of the title company, Account number where the money will be held, Phone number of the title company","Name of the owner of the title company, Address, Phone number, and email address"}	0	{"correct": "According to the Florida Administrative Code (Rule 61J2-14.008), when an escrow deposit is placed with a title company or an attorney, the licensee who prepares or presents the sales contract must indicate the name, address, and telephone number of that title company or attorney on the contract. Note that writing \\"TBD\\" (To Be Determined) is not acceptable and violates this rule.", "incorrect": ["", "While the name of an attorney must be included if the attorney is acting as the escrow agent, if a title company is the agent, you do not need to list the specific name, address, and phone number of the title company's internal attorney.", "The actual bank account number where the money will be held is highly sensitive information and is not required (nor is it safe) to be broadcasted on the face of the purchase and sale agreement.", "The email address is often helpful and frequently included in modern practice, but it is not strictly required by the specific FREC rule. Additionally, the name of the owner of the title company is not required; only the name of the company itself."]}	34	chapter	2026-02-19 19:27:32.803	2026-02-19 20:01:36.547	\N	\N	\N	\N	/audio/1771531290944-According_to_the_Flo.mp3	/timestamps/1771531290944-According_to_the_Flo.timestamps.json	["", "/audio/1771531292921-While_the_name_of_an.mp3", "/audio/1771531294425-The_actual_bank_acco.mp3", "/audio/1771531296355-The_email_address_is.mp3"]	["", "/timestamps/1771531292921-While_the_name_of_an.timestamps.json", "/timestamps/1771531294425-The_actual_bank_acco.timestamps.json", "/timestamps/1771531296355-The_email_address_is.timestamps.json"]	["/audio/1771531285094-Address__telephone_n.mp3", "/audio/1771531285961-Name__phone_and_emai.mp3", "/audio/1771531287053-The_name_of_the_titl.mp3", "/audio/1771531287952-Name_of_the_owner_of.mp3"]	["/timestamps/1771531285094-Address__telephone_n.timestamps.json", "/timestamps/1771531285961-Name__phone_and_emai.timestamps.json", "/timestamps/1771531287053-The_name_of_the_titl.timestamps.json", "/timestamps/1771531287952-Name_of_the_owner_of.timestamps.json"]	/audio/1771531284197-When_a_real_estate_c.mp3	/timestamps/1771531284197-When_a_real_estate_c.timestamps.json
cmltuw4yv00qrr4evkd0tzp5j	cmlslqsgt00l1r4evfhnwe7be	The Sunshine team is ordering For Sale signs. They work for ABC Realty. Which statement is FALSE?	{"The name of the Sunshine Team may not be larger than ABC Realty","The name ABC Realty must be included on the sign","The name of the listing agent must be included on the sign","If the agent's name is included, their last name must appear as registered with DBPR"}	2	{"correct": "FREC rules do NOT mandate that an individual listing agent's name be placed on advertising (such as a yard sign). The only name strictly required by law on all real estate advertisements is the licensed name of the brokerage firm.", "incorrect": ["According to FREC Rule 61J2-10.026 regarding Team Advertising, the team or group name shall not be in larger print than the name of the registered brokerage.", "According to FREC Rule 61J2-10.025, all real estate advertisements must include the licensed name of the brokerage firm.", "", "While an agent isn't required to put their name on a sign, if they do choose to include it, FREC requires that at the very least, their last name must be used exactly as it is registered with the Commission."]}	35	chapter	2026-02-19 19:30:46.183	2026-02-19 20:01:48.444	\N	\N	\N	\N	/audio/1771531303566-FREC_rules_do_NOT_ma.mp3	/timestamps/1771531303566-FREC_rules_do_NOT_ma.timestamps.json	["/audio/1771531305303-According_to_FREC_Ru.mp3", "/audio/1771531306703-According_to_FREC_Ru.mp3", "", "/audio/1771531308258-While_an_agent_isn_t.mp3"]	["/timestamps/1771531305303-According_to_FREC_Ru.timestamps.json", "/timestamps/1771531306703-According_to_FREC_Ru.timestamps.json", "", "/timestamps/1771531308258-While_an_agent_isn_t.timestamps.json"]	["/audio/1771531298887-The_name_of_the_Suns.mp3", "/audio/1771531299684-The_name_ABC_Realty_.mp3", "/audio/1771531300485-The_name_of_the_list.mp3", "/audio/1771531301441-If_the_agent_s_name_.mp3"]	["/timestamps/1771531298887-The_name_of_the_Suns.timestamps.json", "/timestamps/1771531299684-The_name_ABC_Realty_.timestamps.json", "/timestamps/1771531300485-The_name_of_the_list.timestamps.json", "/timestamps/1771531301441-If_the_agent_s_name_.timestamps.json"]	/audio/1771531297951-The_Sunshine_team_is.mp3	/timestamps/1771531297951-The_Sunshine_team_is.timestamps.json
cmltvdjna00qwr4ev9xya1wbg	cmlslqsgt00l1r4evfhnwe7be	What is the primary difference in liability between a general partnership and a limited partnership?	{"In a general partnership, only the managing partners are liable, while in a limited partnership, all investors share equal full liability","In a general partnership, every partner is personally liable for the company's debts, whereas in a limited partnership, limited partners' liability is restricted to their investment amount"," Both general and limited partnerships offer full personal liability protection for all partners, similar to a corporation","A general partnership is a prohibited structure where brokers share an office without a formal agreement, while a limited partnership is legally recognized"}	1	{"correct": "In a general partnership, all partners share full personal liability for the business's debts and mistakes. In a limited partnership, the general partners take on full liability and run the business, while the limited partners are simply investors whose financial risk is capped at the amount of money they put in.", "incorrect": ["This incorrectly reverses the roles. In a general partnership, every partner is fully liable. In a limited partnership, the limited partners specifically do not have full liability.", "In a general partnership, all partners share full personal liability for the business's debts and mistakes. In a limited partnership, the general partners take on full liability and run the business, while the limited partners are simply investors whose financial risk is capped at the amount of money they put in.", "Neither partnership structure offers full liability protection for all members. There must always be at least one general partner who assumes full personal liability for the company's debts.", "This option incorrectly describes an \\"Ostensible Partnership\\" (a fake, prohibited partnership where people just act like partners to the public). A true general partnership is a fully legal and recognized business structure."]}	36	chapter	2026-02-19 19:44:18.358	2026-02-19 20:02:05.654	\N	\N	\N	\N	/audio/1771531318153-In_a_general_partner.mp3	/timestamps/1771531318153-In_a_general_partner.timestamps.json	["/audio/1771531320146-This_incorrectly_rev.mp3", "/audio/1771531322214-In_a_general_partner.mp3", "/audio/1771531323703-Neither_partnership_.mp3", "/audio/1771531325485-This_option_incorrec.mp3"]	["/timestamps/1771531320146-This_incorrectly_rev.timestamps.json", "/timestamps/1771531322214-In_a_general_partner.timestamps.json", "/timestamps/1771531323703-Neither_partnership_.timestamps.json", "/timestamps/1771531325485-This_option_incorrec.timestamps.json"]	["/audio/1771531311498-In_a_general_partner.mp3", "/audio/1771531313019-In_a_general_partner.mp3", "/audio/1771531314298-Both_general_and_lim.mp3", "/audio/1771531315725-A_general_partnershi.mp3"]	["/timestamps/1771531311498-In_a_general_partner.timestamps.json", "/timestamps/1771531313019-In_a_general_partner.timestamps.json", "/timestamps/1771531314298-Both_general_and_lim.timestamps.json", "/timestamps/1771531315725-A_general_partnershi.timestamps.json"]	/audio/1771531310168-What_is_the_primary_.mp3	/timestamps/1771531310168-What_is_the_primary_.timestamps.json
cmmqfwmg900344be7orq2xnvh	cmmqbpz7v00044be7x0za79d7	Which practice involves inducing homeowners to sell by predicting that members of a protected class are moving into the neighborhood?	{Steering,Redlining,Blockbusting,Commingling}	2	{"correct": "Blockbusting (also called panic peddling) is the illegal act of inducing panic selling for profit by exploiting racial prejudice.", "incorrect": ["Steering is directing buyers to/away from neighborhoods.", "Redlining is denying loans/insurance by geography.", "", "Commingling is mixing escrow funds with personal funds.<div><br></div>"]}	12	chapter	2026-03-14 14:47:38.409	2026-03-14 23:13:07.932	\N	\N	\N	\N	/audio/1773529984761-Blockbusting__also_c.mp3	/timestamps/1773529984761-Blockbusting__also_c.timestamps.json	["/audio/1773529985862-Steering_is_directin.mp3", "/audio/1773529986837-Redlining_is_denying.mp3", "", "/audio/1773529987702-Commingling_is_mixin.mp3"]	["/timestamps/1773529985862-Steering_is_directin.timestamps.json", "/timestamps/1773529986837-Redlining_is_denying.timestamps.json", "", "/timestamps/1773529987702-Commingling_is_mixin.timestamps.json"]	["/audio/1773529981144-Steering.mp3", "/audio/1773529981759-Redlining.mp3", "/audio/1773529982376-Blockbusting.mp3", "/audio/1773529983108-Commingling.mp3"]	["/timestamps/1773529981144-Steering.timestamps.json", "/timestamps/1773529981759-Redlining.timestamps.json", "/timestamps/1773529982376-Blockbusting.timestamps.json", "/timestamps/1773529983108-Commingling.timestamps.json"]	/audio/1773529980569-Which_practice_invol.mp3	/timestamps/1773529980569-Which_practice_invol.timestamps.json
cmmcmw80p002l3v02283evbuu	cmm58y7lt002j3t2wepydt1xl	What is the immediate professional consequence for a licensee if the Real Estate Recovery Fund pays out a claim to satisfy a judgment against them (that did NOT involve an Escrow Disbursement Order)?	{"The license is automatically suspended until the money is repaid","The license is revoked permanently with no possibility of reinstatement.","The licensee is placed on probation for 10 years.","There is no penalty if the licensee files for bankruptcy."}	0	{"correct": "Payment from the fund results in the mandatory, automatic suspension of the license. The suspension lasts until the licensee repays the full amount to the fund, plus interest.", "incorrect": ["", "It is not necessarily permanent revocation; the license can be reinstated once the money is paid back.", "Probation is a different penalty; the statute specifically mandates suspension for fund payouts.", "Filing for bankruptcy does not relieve the licensee of the penalty. The suspension stands until the fund is reimbursed."]}	3	chapter	2026-03-04 22:54:30.553	2026-03-04 23:35:34.506	\N	\N	\N	\N	/audio/1772667329930-Payment_from_the_fun.mp3	/timestamps/1772667329930-Payment_from_the_fun.timestamps.json	["", "/audio/1772667331197-It_is_not_necessaril.mp3", "/audio/1772667332747-Probation_is_a_diffe.mp3", "/audio/1772667334246-Filing_for_bankruptc.mp3"]	["", "/timestamps/1772667331197-It_is_not_necessaril.timestamps.json", "/timestamps/1772667332747-Probation_is_a_diffe.timestamps.json", "/timestamps/1772667334246-Filing_for_bankruptc.timestamps.json"]	null	null	\N	\N
cmmcmu2za002j3v02fn3f3329	cmm58y7lt002j3t2wepydt1xl	A licensed real estate broker commits fraud, causing a financial loss to several parties. Which of the following individuals would be ELIGIBLE to file a claim against the Real Estate Recovery Fund?	{"The broker’s spouse, who lent money to the business","A sales associate who was not paid their commission on the deal","A buyer who obtained a final civil judgment against the broker and discovered the broker has no assets","A seller who sued the brokerage corporation (entity) but not the individual broker"}	2	{"correct": "To claim from the fund, the injured party must be a consumer (not a licensee) who has already won a Final Judgment in court and attempted to collect, but found the licensee to be \\"judgment proof\\" (broke).", "incorrect": ["The spouse of the offending licensee is strictly prohibited from making a claim.", "A licensee (sales associate or broker) cannot claim against the fund for business disputes or commission losses.", "", "The claim must be based on a judgment against the individual licensee, not just the brokerage entity/company."]}	2	chapter	2026-03-04 22:52:50.71	2026-03-04 23:34:33.038	\N	\N	\N	\N	/audio/1772667266153-To_claim_from_the_fu.mp3	/timestamps/1772667266153-To_claim_from_the_fu.timestamps.json	["/audio/1772667267095-The_spouse_of_the_of.mp3", "/audio/1772667268239-A_licensee__sales_as.mp3", "", "/audio/1772667269997-The_claim_must_be_ba.mp3"]	["/timestamps/1772667267095-The_spouse_of_the_of.timestamps.json", "/timestamps/1772667268239-A_licensee__sales_as.timestamps.json", "", "/timestamps/1772667269997-The_claim_must_be_ba.timestamps.json"]	["/audio/1772667262032-The_broker_s_spouse_.mp3", "/audio/1772667262761-A_sales_associate_wh.mp3", "/audio/1772667263677-A_buyer_who_obtained.mp3", "/audio/1772667264582-A_seller_who_sued_th.mp3"]	["/timestamps/1772667262032-The_broker_s_spouse_.timestamps.json", "/timestamps/1772667262761-A_sales_associate_wh.timestamps.json", "/timestamps/1772667263677-A_buyer_who_obtained.timestamps.json", "/timestamps/1772667264582-A_seller_who_sued_th.timestamps.json"]	/audio/1772667261346-A_licensed_real_esta.mp3	/timestamps/1772667261346-A_licensed_real_esta.timestamps.json
cmmcmmjkp002f3v02lhlb25cs	cmm58y7lt002j3t2wepydt1xl	Which of the following limits regarding the Florida Real Estate Recovery Fund is ACCURATE?	{"The fund covers punitive damages up to $50,000","The maximum payout for a single transaction is $50,000, regardless of the number of claimants","The maximum payout for multiple judgments against one licensee is $1,000,000","The fund will reimburse the injured party for their attorney's fees and court costs in all cases of fraud"}	1	{"correct": "The liability of the fund is capped at $50,000 for any one transaction (deal). Even if five different people lost money in that one deal, the fund only gives $50,000 total to be split among them.", "incorrect": ["The fund pays compensatory damages only (actual money lost). It generally does not pay punitive damages, treble damages, or interest.<div><br></div><div><br></div>", "", "The aggregate lifetime limit for claims against a single licensee is $150,000, not $1 million.", "The fund generally does not cover attorney’s fees or court costs (unless the broker was complying with an EDO)."]}	0	chapter	2026-03-04 22:46:58.969	2026-03-04 23:34:07.267	\N	\N	\N	\N	/audio/1772667243246-The_liability_of_the.mp3	/timestamps/1772667243246-The_liability_of_the.timestamps.json	["/audio/1772667244782-The_fund_pays_compen.mp3", "", "/audio/1772667245995-The_aggregate_lifeti.mp3", "/audio/1772667247025-The_fund_generally_d.mp3"]	["/timestamps/1772667244782-The_fund_pays_compen.timestamps.json", "", "/timestamps/1772667245995-The_aggregate_lifeti.timestamps.json", "/timestamps/1772667247025-The_fund_generally_d.timestamps.json"]	["/audio/1772667238279-The_fund_covers_puni.mp3", "/audio/1772667239263-The_maximum_payout_f.mp3", "/audio/1772667240191-The_maximum_payout_f.mp3", "/audio/1772667241242-The_fund_will_reimbu.mp3"]	["/timestamps/1772667238279-The_fund_covers_puni.timestamps.json", "/timestamps/1772667239263-The_maximum_payout_f.timestamps.json", "/timestamps/1772667240191-The_maximum_payout_f.timestamps.json", "/timestamps/1772667241242-The_fund_will_reimbu.timestamps.json"]	/audio/1772667237511-Which_of_the_followi.mp3	/timestamps/1772667237511-Which_of_the_followi.timestamps.json
cmmqg01wd00364be7e2vcd14b	cmmqbpz7v00044be7x0za79d7	An agent shows a Hispanic buyer homes only in neighborhoods with a high Hispanic population, assuming they would "fit in better" there. This is an example of:	{Redlining,Steering,Blockbusting,"Due Diligence"}	1	{"correct": "Steering is channeling homeseekers to or away from specific neighborhoods based on their protected class.", "incorrect": ["Redlining involves lenders/insurers.", "", "Blockbusting involves inducing sellers to sell.", "Due diligence is the proper investigation of facts, not discrimination."]}	13	chapter	2026-03-14 14:50:18.397	2026-03-14 23:13:16.849	\N	\N	\N	\N	/audio/1773529993847-Steering_is_channeli.mp3	/timestamps/1773529993847-Steering_is_channeli.timestamps.json	["/audio/1773529994788-Redlining_involves_l.mp3", "", "/audio/1773529995647-Blockbusting_involve.mp3", "/audio/1773529996694-Due_diligence_is_the.mp3"]	["/timestamps/1773529994788-Redlining_involves_l.timestamps.json", "", "/timestamps/1773529995647-Blockbusting_involve.timestamps.json", "/timestamps/1773529996694-Due_diligence_is_the.timestamps.json"]	["/audio/1773529990587-Redlining.mp3", "/audio/1773529991185-Steering.mp3", "/audio/1773529991819-Blockbusting.mp3", "/audio/1773529992379-Due_Diligence.mp3"]	["/timestamps/1773529990587-Redlining.timestamps.json", "/timestamps/1773529991185-Steering.timestamps.json", "/timestamps/1773529991819-Blockbusting.timestamps.json", "/timestamps/1773529992379-Due_Diligence.timestamps.json"]	/audio/1773529989977-An_agent_shows_a_His.mp3	/timestamps/1773529989977-An_agent_shows_a_His.timestamps.json
cmmqg3dye00384be7la3woklr	cmmqbpz7v00044be7x0za79d7	A mortgage lender refuses to provide loans for homes in a specific zip code because of the racial makeup of the area. This practice is known as:	{Steering,Blockbusting,Redlining,"Price Fixing"}	2	{"correct": "Redlining is the refusal to offer credit or insurance in certain geographic areas for discriminatory reasons (literally drawing a red line on the map).", "incorrect": ["Steering involves showing houses.", "Blockbusting involves panic selling.", "", "Price fixing is an antitrust violation among competitors."]}	14	chapter	2026-03-14 14:52:53.99	2026-03-14 23:13:25.952	\N	\N	\N	\N	/audio/1773530003201-Redlining_is_the_ref.mp3	/timestamps/1773530003201-Redlining_is_the_ref.timestamps.json	["/audio/1773530004106-Steering_involves_sh.mp3", "/audio/1773530004821-Blockbusting_involve.mp3", "", "/audio/1773530005744-Price_fixing_is_an_a.mp3"]	["/timestamps/1773530004106-Steering_involves_sh.timestamps.json", "/timestamps/1773530004821-Blockbusting_involve.timestamps.json", "", "/timestamps/1773530005744-Price_fixing_is_an_a.timestamps.json"]	["/audio/1773529999370-Steering.mp3", "/audio/1773530000195-Blockbusting.mp3", "/audio/1773530000782-Redlining.mp3", "/audio/1773530001417-Price_Fixing.mp3"]	["/timestamps/1773529999370-Steering.timestamps.json", "/timestamps/1773530000195-Blockbusting.timestamps.json", "/timestamps/1773530000782-Redlining.timestamps.json", "/timestamps/1773530001417-Price_Fixing.timestamps.json"]	/audio/1773529998823-A_mortgage_lender_re.mp3	/timestamps/1773529998823-A_mortgage_lender_re.timestamps.json
cmmcmqyef002h3v02lkc94xeb	cmm58y7lt002j3t2wepydt1xl	Under what specific circumstance is a Summary (Emergency) Suspension Order issued, and who has the authority to issue it?	{"It is issued by the FREC Chairperson when a licensee fails to pay an administrative fine within 30 days","It is issued by the DBPR Secretary (or their designee) when a licensee’s actions pose an immediate danger to the public health, safety, or welfare","It is issued by the Administrative Law Judge (ALJ) immediately following a formal hearing if the evidence is overwhelming","It is issued by the Probable-Cause Panel when they receive a second anonymous complaint against the same licensee"}	1	{"correct": "A Summary Suspension is an emergency measure taken before the legal process is finished. If the DBPR Secretary determines that allowing the licensee to continue practicing during the investigation would endanger the public (e.g., a broker stealing funds or committing violence), they can suspend the license immediately.", "incorrect": ["Failure to pay a fine results in disciplinary action, but not usually an emergency suspension, and the FREC Chairperson does not issue these orders unilaterally.", "", "An ALJ submits a Recommended Order; they do not have the authority to issue a final suspension order or an emergency suspension.", "The Probable-Cause Panel directs the filing of a formal complaint; they do not have the power to suspend a license."]}	1	chapter	2026-03-04 22:50:24.807	2026-03-04 23:34:19.862	\N	\N	\N	\N	/audio/1772667255735-A_Summary_Suspension.mp3	/timestamps/1772667255735-A_Summary_Suspension.timestamps.json	["/audio/1772667257277-Failure_to_pay_a_fin.mp3", "", "/audio/1772667258426-An_ALJ_submits_a_Rec.mp3", "/audio/1772667259644-The_Probable_Cause_P.mp3"]	["/timestamps/1772667257277-Failure_to_pay_a_fin.timestamps.json", "", "/timestamps/1772667258426-An_ALJ_submits_a_Rec.timestamps.json", "/timestamps/1772667259644-The_Probable_Cause_P.timestamps.json"]	["/audio/1772667249821-It_is_issued_by_the_.mp3", "/audio/1772667251173-It_is_issued_by_the_.mp3", "/audio/1772667252250-It_is_issued_by_the_.mp3", "/audio/1772667253345-It_is_issued_by_the_.mp3"]	["/timestamps/1772667249821-It_is_issued_by_the_.timestamps.json", "/timestamps/1772667251173-It_is_issued_by_the_.timestamps.json", "/timestamps/1772667252250-It_is_issued_by_the_.timestamps.json", "/timestamps/1772667253345-It_is_issued_by_the_.timestamps.json"]	/audio/1772667248635-Under_what_specific_.mp3	/timestamps/1772667248635-Under_what_specific_.timestamps.json
cmmcmyu4h002n3v02jdhkhm51	cmm58y7lt002j3t2wepydt1xl	Who has the sole authority to determine whether probable cause exists to believe a licensee has violated Chapter 475?&nbsp;	{"The Administrative Law Judge (ALJ) ","The Department of Business and Professional Regulation (DBPR) investigator","The Probable-Cause Panel ","The Florida Real Estate Commission (FREC) acting as a whole body"}	2	{"correct": "The Probable-Cause Panel (composed of two members) is the specific body tasked with reviewing the investigative report to determine if there is enough evidence to file a formal administrative complaint.", "incorrect": ["The ALJ hears the case only after probable cause has been found and the licensee disputes the allegations.", "The DBPR investigator gathers the facts and prepares the report, but they do not have the authority to make the legal decision regarding probable cause.", "", "The full FREC does not decide probable cause. In fact, the panel members are excused from the final hearing to prevent bias, ensuring the remaining commissioners act as an impartial \\"jury.\\""]}	4	chapter	2026-03-04 22:56:32.513	2026-03-04 23:35:57.925	\N	\N	\N	\N	/audio/1772667340824-The_Probable_Cause_P.mp3	/timestamps/1772667340824-The_Probable_Cause_P.timestamps.json	["/audio/1772667342152-The_ALJ_hears_the_ca.mp3", "/audio/1772667344375-The_DBPR_investigato.mp3", "", ""]	["/timestamps/1772667342152-The_ALJ_hears_the_ca.timestamps.json", "/timestamps/1772667344375-The_DBPR_investigato.timestamps.json", "", ""]	["/audio/1772667336738-The_Administrative_L.mp3", "/audio/1772667337651-The_Department_of_Bu.mp3", "/audio/1772667338290-The_Probable_Cause_P.mp3", "/audio/1772667339232-The_Florida_Real_Est.mp3"]	["/timestamps/1772667336738-The_Administrative_L.timestamps.json", "/timestamps/1772667337651-The_Department_of_Bu.timestamps.json", "/timestamps/1772667338290-The_Probable_Cause_P.timestamps.json", "/timestamps/1772667339232-The_Florida_Real_Est.timestamps.json"]	/audio/1772667336108-Who_has_the_sole_aut.mp3	/timestamps/1772667336108-Who_has_the_sole_aut.timestamps.json
cmmqg5hvq003a4be7bdc2wx83	cmmqbpz7v00044be7x0za79d7	A client asks you to list their "Mrs. Murphy" eligible duplex (where they live) but instructs you not to show it to families with children. What must you do?	{"Follow the client's instructions because they are exempt","Charge a higher commission for the extra work","Refuse the listing because a real estate licensee cannot participate in discrimination","List the property but only show it to families with children to balance it out"}	2	{"correct": "Even if the owner could discriminate legally on their own, the moment they hire you (a licensee), the exemption is lost. You cannot violate Fair Housing laws. You must refuse the listing.", "incorrect": ["The exemption does not apply when a broker is involved.", "You cannot participate in the discriminatory transaction at all.", "", "You cannot participate in the discriminatory transaction at all."]}	15	chapter	2026-03-14 14:54:32.389	2026-03-14 23:13:37.551	\N	\N	\N	\N	/audio/1773530014380-Even_if_the_owner_co.mp3	/timestamps/1773530014380-Even_if_the_owner_co.timestamps.json	["/audio/1773530015581-The_exemption_does_n.mp3", "/audio/1773530016440-You_cannot_participa.mp3", "", "/audio/1773530017397-You_cannot_participa.mp3"]	["/timestamps/1773530015581-The_exemption_does_n.timestamps.json", "/timestamps/1773530016440-You_cannot_participa.timestamps.json", "", "/timestamps/1773530017397-You_cannot_participa.timestamps.json"]	["/audio/1773530008737-Follow_the_client_s_.mp3", "/audio/1773530009702-Charge_a_higher_comm.mp3", "/audio/1773530011013-Refuse_the_listing_b.mp3", "/audio/1773530012409-List_the_property_bu.mp3"]	["/timestamps/1773530008737-Follow_the_client_s_.timestamps.json", "/timestamps/1773530009702-Charge_a_higher_comm.timestamps.json", "/timestamps/1773530011013-Refuse_the_listing_b.timestamps.json", "/timestamps/1773530012409-List_the_property_bu.timestamps.json"]	/audio/1773530007697-A_client_asks_you_to.mp3	/timestamps/1773530007697-A_client_asks_you_to.timestamps.json
cmmcn0uqi002p3v02hexv8v8d	cmm58y7lt002j3t2wepydt1xl	Under what specific condition is the Division of Real Estate (DRE) authorized to investigate a written complaint filed against a licensee?	{"When the complaint is legally sufficient, meaning it contains facts that, if true, would indicate a violation of Florida statute or FREC rule","Immediately upon receipt of any consumer dissatisfaction, regardless of whether a law was broken","Only if the complainant has suffered a documented financial loss of at least $1,000","Only after the licensee has admitted to the allegation in writing"}	0	{"correct": "The DRE is only empowered to investigate complaints that are \\"legally sufficient.\\" This means the complaint must allege specific facts that, if proven true, would constitute a violation of Chapter 475, Chapter 455, or FREC rules. They do not investigate generic poor service.", "incorrect": ["", "The DRE does not investigate complaints solely based on customer dissatisfaction (like rudeness) unless that behavior also constitutes a specific legal violation.", "Financial loss is not a requirement for an investigation. A licensee can be investigated for non-monetary violations, such as failure to display a proper sign or advertising errors.", "The DRE investigates to determine if a violation occurred. They do not wait for a confession or admission of guilt to begin their inquiry."]}	5	chapter	2026-03-04 22:58:06.618	2026-03-04 23:36:14.911	\N	\N	\N	\N	/audio/1772667368464-The_DRE_is_only_empo.mp3	/timestamps/1772667368464-The_DRE_is_only_empo.timestamps.json	["", "/audio/1772667370352-The_DRE_does_not_inv.mp3", "/audio/1772667372291-Financial_loss_is_no.mp3", "/audio/1772667374432-The_DRE_investigates.mp3"]	["", "/timestamps/1772667370352-The_DRE_does_not_inv.timestamps.json", "/timestamps/1772667372291-Financial_loss_is_no.timestamps.json", "/timestamps/1772667374432-The_DRE_investigates.timestamps.json"]	["/audio/1772667361566-When_the_complaint_i.mp3", "/audio/1772667363177-Immediately_upon_rec.mp3", "/audio/1772667364703-Only_if_the_complain.mp3", "/audio/1772667365852-Only_after_the_licen.mp3"]	["/timestamps/1772667361566-When_the_complaint_i.timestamps.json", "/timestamps/1772667363177-Immediately_upon_rec.timestamps.json", "/timestamps/1772667364703-Only_if_the_complain.timestamps.json", "/timestamps/1772667365852-Only_after_the_licen.timestamps.json"]	/audio/1772667359553-Under_what_specific_.mp3	/timestamps/1772667359553-Under_what_specific_.timestamps.json
cmmqg6xzv003c4be7m9s2qpe3	cmmqbpz7v00044be7x0za79d7	Under the Americans with Disabilities Act (ADA), a real estate brokerage office is considered a:	{"Private club","Place of public accommodation","Residential dwelling","Government facility"}	1	{"correct": "A real estate office is a place of public accommodation. Therefore, it must be accessible to people with disabilities (ramps, wide doors, etc.).", "incorrect": ["Offices are open to the public, not just members.", "", "It is a commercial facility, not residential.", "It is a private business, not government-owned."]}	16	chapter	2026-03-14 14:55:39.931	2026-03-14 23:13:46.946	\N	\N	\N	\N	/audio/1773530023633-A_real_estate_office.mp3	/timestamps/1773530023633-A_real_estate_office.timestamps.json	["/audio/1773530024567-Offices_are_open_to_.mp3", "", "/audio/1773530025452-It_is_a_commercial_f.mp3", "/audio/1773530026694-It_is_a_private_busi.mp3"]	["/timestamps/1773530024567-Offices_are_open_to_.timestamps.json", "", "/timestamps/1773530025452-It_is_a_commercial_f.timestamps.json", "/timestamps/1773530026694-It_is_a_private_busi.timestamps.json"]	["/audio/1773530019403-Private_club.mp3", "/audio/1773530020205-Place_of_public_acco.mp3", "/audio/1773530020979-Residential_dwelling.mp3", "/audio/1773530021572-Government_facility.mp3"]	["/timestamps/1773530019403-Private_club.timestamps.json", "/timestamps/1773530020205-Place_of_public_acco.timestamps.json", "/timestamps/1773530020979-Residential_dwelling.timestamps.json", "/timestamps/1773530021572-Government_facility.timestamps.json"]	/audio/1773530018854-Under_the_Americans_.mp3	/timestamps/1773530018854-Under_the_Americans_.timestamps.json
cmmcn47eh002r3v026rqsh3mi	cmm58y7lt002j3t2wepydt1xl	A licensee receives a formal administrative complaint but fails to return the "Election of Rights" form within the statutory 21-day period. What is the legal consequence of this inaction?&nbsp;	{"The complaint is automatically dismissed due to lack of participation","The licensee is considered to have waived their rights to be heard, and the FREC will proceed with the disposition of the case in their absence","The case is automatically forwarded to an Administrative Law Judge for a formal hearing","The licensee’s license is immediately revoked without any further hearing"}	1	{"correct": "Failure to respond is considered a Waiver of Rights. The FREC proceeds with the case (usually in an informal \\"Waiver Hearing\\"), accepts the allegations as true, and imposes discipline without the licensee present to defend themselves.", "incorrect": ["Ignoring a legal complaint never results in dismissal; it results in a default judgment against you.", "", "A formal hearing is only required if there is a dispute of material fact. By not responding, the licensee has not disputed anything, so no formal hearing is necessary.", "The revocation is not \\"immediate\\" or \\"automatic\\" upon the deadline passing. The FREC must still meet, review the case, and vote on the Final Order, even if the licensee isn't there."]}	6	chapter	2026-03-04 23:00:43.001	2026-03-04 23:36:31.874	\N	\N	\N	\N	/audio/1772667387211-Failure_to_respond_i.mp3	/timestamps/1772667387211-Failure_to_respond_i.timestamps.json	["/audio/1772667388579-Ignoring_a_legal_com.mp3", "", "/audio/1772667390139-A_formal_hearing_is_.mp3", "/audio/1772667391662-The_revocation_is_no.mp3"]	["/timestamps/1772667388579-Ignoring_a_legal_com.timestamps.json", "", "/timestamps/1772667390139-A_formal_hearing_is_.timestamps.json", "/timestamps/1772667391662-The_revocation_is_no.timestamps.json"]	["/audio/1772667378616-The_complaint_is_aut.mp3", "/audio/1772667380719-The_licensee_is_cons.mp3", "/audio/1772667383128-The_case_is_automati.mp3", "/audio/1772667384026-The_licensee_s_licen.mp3"]	["/timestamps/1772667378616-The_complaint_is_aut.timestamps.json", "/timestamps/1772667380719-The_licensee_is_cons.timestamps.json", "/timestamps/1772667383128-The_case_is_automati.timestamps.json", "/timestamps/1772667384026-The_licensee_s_licen.timestamps.json"]	/audio/1772667377423-A_licensee_receives_.mp3	/timestamps/1772667377423-A_licensee_receives_.timestamps.json
cmmqg91pa003e4be7r2g02pyx	cmmqbpz7v00044be7x0za79d7	&nbsp;The Interstate Land Sales Full Disclosure Act requires developers to register with the Consumer Financial Protection Bureau if they are selling subdivisions of how many lots across state lines?	{"25 or more","50 or more","100 or more","500 or more"}	2	{"correct": "Developers of 100 or more lots must register with the CFPB.", "incorrect": ["25 is the threshold for providing a property report, but registration is for 100+.", "The statutory number is 100.", "", "The statutory number is 100."]}	17	chapter	2026-03-14 14:57:18.046	2026-03-14 23:13:55.547	\N	\N	\N	\N	/audio/1773530032480-Developers_of_100_or.mp3	/timestamps/1773530032480-Developers_of_100_or.timestamps.json	["/audio/1773530033789-25_is_the_threshold_.mp3", "/audio/1773530034473-The_statutory_number.mp3", "", "/audio/1773530035318-The_statutory_number.mp3"]	["/timestamps/1773530033789-25_is_the_threshold_.timestamps.json", "/timestamps/1773530034473-The_statutory_number.timestamps.json", "", "/timestamps/1773530035318-The_statutory_number.timestamps.json"]	["/audio/1773530029503-25_or_more.mp3", "/audio/1773530030069-50_or_more.mp3", "/audio/1773530030648-100_or_more.mp3", "/audio/1773530031376-500_or_more.mp3"]	["/timestamps/1773530029503-25_or_more.timestamps.json", "/timestamps/1773530030069-50_or_more.timestamps.json", "/timestamps/1773530030648-100_or_more.timestamps.json", "/timestamps/1773530031376-500_or_more.timestamps.json"]	/audio/1773530028931-The_Interstate_Land_.mp3	/timestamps/1773530028931-The_Interstate_Land_.timestamps.json
cmmqgav1w003g4be70ial2q6h	cmmqbpz7v00044be7x0za79d7	The purpose of the Florida Residential Landlord and Tenant Act is to:	{"Allow landlords to evict tenants without cause.","Equalize the rights and obligations of landlords and tenants.","Set maximum rent control prices for the state.","Require all landlords to use a real estate broker."}	1	{"correct": "The Act (Chapter 83) is designed to place landlords and tenants on an equitable basis, defining the duties of both parties.", "incorrect": ["Evictions must follow strict legal procedures.", "", "Florida does not have statewide rent control in this Act.", "Landlords can manage their own properties."]}	18	chapter	2026-03-14 14:58:42.74	2026-03-14 23:14:04.865	\N	\N	\N	\N	/audio/1773530041668-The_Act__Chapter_83_.mp3	/timestamps/1773530041668-The_Act__Chapter_83_.timestamps.json	["/audio/1773530042987-Evictions_must_follo.mp3", "", "/audio/1773530043817-Florida_does_not_hav.mp3", "/audio/1773530044653-Landlords_can_manage.mp3"]	["/timestamps/1773530042987-Evictions_must_follo.timestamps.json", "", "/timestamps/1773530043817-Florida_does_not_hav.timestamps.json", "/timestamps/1773530044653-Landlords_can_manage.timestamps.json"]	["/audio/1773530037608-Allow_landlords_to_e.mp3", "/audio/1773530038330-Equalize_the_rights_.mp3", "/audio/1773530039068-Set_maximum_rent_con.mp3", "/audio/1773530039923-Require_all_landlord.mp3"]	["/timestamps/1773530037608-Allow_landlords_to_e.timestamps.json", "/timestamps/1773530038330-Equalize_the_rights_.timestamps.json", "/timestamps/1773530039068-Set_maximum_rent_con.timestamps.json", "/timestamps/1773530039923-Require_all_landlord.timestamps.json"]	/audio/1773530036849-The_purpose_of_the_F.mp3	/timestamps/1773530036849-The_purpose_of_the_F.timestamps.json
cmmqgdiix003i4be74hsozbre	cmmqbpz7v00044be7x0za79d7	Which Florida Statute specifically governs the residential landlord-tenant relationship?	{"Chapter 475","Chapter 455","Chapter 83, Part II","Chapter 120"}	2	{"correct": "Chapter 83, Part II is the Florida Residential Landlord and Tenant Act.", "incorrect": ["Chapter 475 is Real Estate License Law.", "Chapter 455 is DBPR Business &amp; Professional Regulation.", "", "Chapter 120 is the Administrative Procedure Act."]}	19	chapter	2026-03-14 15:00:46.473	2026-03-14 23:14:13.79	\N	\N	\N	\N	/audio/1773530050346-Chapter_83__Part_II_.mp3	/timestamps/1773530050346-Chapter_83__Part_II_.timestamps.json	["/audio/1773530051291-Chapter_475_is_Real_.mp3", "/audio/1773530052611-Chapter_455_is_DBPR_.mp3", "", "/audio/1773530053638-Chapter_120_is_the_A.mp3"]	["/timestamps/1773530051291-Chapter_475_is_Real_.timestamps.json", "/timestamps/1773530052611-Chapter_455_is_DBPR_.timestamps.json", "", "/timestamps/1773530053638-Chapter_120_is_the_A.timestamps.json"]	["/audio/1773530046775-Chapter_475.mp3", "/audio/1773530047623-Chapter_455.mp3", "/audio/1773530048540-Chapter_83__Part_II.mp3", "/audio/1773530049284-Chapter_120.mp3"]	["/timestamps/1773530046775-Chapter_475.timestamps.json", "/timestamps/1773530047623-Chapter_455.timestamps.json", "/timestamps/1773530048540-Chapter_83__Part_II.timestamps.json", "/timestamps/1773530049284-Chapter_120.timestamps.json"]	/audio/1773530045941-Which_Florida_Statut.mp3	/timestamps/1773530045941-Which_Florida_Statut.timestamps.json
cmmcn69k1002t3v02raeomnys	cmm58y7lt002j3t2wepydt1xl	Which penalty is the Florida Real Estate Commission (FREC) NOT authorized to impose on a licensee?	{"Revocation of the license",Imprisonment,"Administrative fine of up to $5,000 per violation","Suspension of the license for up to 10 years"}	1	{"correct": "The FREC's powers are administrative only. They can affect your license and fine you, but they cannot impose criminal penalties like imprisonment (jail time). Only a criminal court can sentence a licensee to jail.", "incorrect": ["The FREC has the authority to permanently revoke a license, which is the most severe administrative penalty.", "", "The FREC can impose an administrative fine of up to $5,000 for each violation of Chapter 475 or 455.", "The FREC can suspend a license for a maximum period of 10 years."]}	7	chapter	2026-03-04 23:02:19.105	2026-03-04 23:36:45.413	\N	\N	\N	\N	/audio/1772667400687-The_FREC_s_powers_ar.mp3	/timestamps/1772667400687-The_FREC_s_powers_ar.timestamps.json	["/audio/1772667402971-The_FREC_has_the_aut.mp3", "", "/audio/1772667404362-The_FREC_can_impose_.mp3", "/audio/1772667405181-The_FREC_can_suspend.mp3"]	["/timestamps/1772667402971-The_FREC_has_the_aut.timestamps.json", "", "/timestamps/1772667404362-The_FREC_can_impose_.timestamps.json", "/timestamps/1772667405181-The_FREC_can_suspend.timestamps.json"]	["/audio/1772667394323-Revocation_of_the_li.mp3", "/audio/1772667395952-Imprisonment.mp3", "/audio/1772667397599-Administrative_fine_.mp3", "/audio/1772667398534-Suspension_of_the_li.mp3"]	["/timestamps/1772667394323-Revocation_of_the_li.timestamps.json", "/timestamps/1772667395952-Imprisonment.timestamps.json", "/timestamps/1772667397599-Administrative_fine_.timestamps.json", "/timestamps/1772667398534-Suspension_of_the_li.timestamps.json"]	/audio/1772667393666-Which_penalty_is_the.mp3	/timestamps/1772667393666-Which_penalty_is_the.timestamps.json
cmmcn8mu4002v3v02pojv8a72	cmm58y7lt002j3t2wepydt1xl	Which of the following penalties is the Division of Real Estate (DRE) authorized to issue?&nbsp;	{"An administrative fine of up to $5,000 per violation","A citation","Suspension of the license for up to 10 years",Probation}	1	{"correct": "The Division of Real Estate (DRE) has the authority to issue Citations (for minor violations involving fines usually between $100 and $500) and Notices of Noncompliance (for first-time minor offenses). ", "incorrect": ["The authority to impose administrative fines of up to $5,000 lies with the Florida Real Estate Commission (FREC), not the DRE.", "", "Only the FREC has the power to suspend a license.", "Only the FREC can place a licensee on probation. The DRE's powers are generally limited to investigation and issuing minor administrative penalties (citations/notices)."]}	8	chapter	2026-03-04 23:04:09.627	2026-03-04 23:37:00.79	\N	\N	\N	\N	/audio/1772667415355-The_Division_of_Real.mp3	/timestamps/1772667415355-The_Division_of_Real.timestamps.json	["/audio/1772667416974-The_authority_to_imp.mp3", "", "/audio/1772667418325-Only_the_FREC_has_th.mp3", "/audio/1772667420364-Only_the_FREC_can_pl.mp3"]	["/timestamps/1772667416974-The_authority_to_imp.timestamps.json", "", "/timestamps/1772667418325-Only_the_FREC_has_th.timestamps.json", "/timestamps/1772667420364-Only_the_FREC_can_pl.timestamps.json"]	["/audio/1772667408022-An_administrative_fi.mp3", "/audio/1772667409056-A_citation.mp3", "/audio/1772667409957-Suspension_of_the_li.mp3", "/audio/1772667411183-Probation.mp3"]	["/timestamps/1772667408022-An_administrative_fi.timestamps.json", "/timestamps/1772667409056-A_citation.timestamps.json", "/timestamps/1772667409957-Suspension_of_the_li.timestamps.json", "/timestamps/1772667411183-Probation.timestamps.json"]	/audio/1772667407087-Which_of_the_followi.mp3	/timestamps/1772667407087-Which_of_the_followi.timestamps.json
cmmcnac28002x3v02zbmd54bl	cmm58y7lt002j3t2wepydt1xl	Which of the following scenarios would typically result in a real estate license being "revoked without prejudice"?&nbsp;	{"The licensee is found guilty of a fair housing violation","The DBPR inadvertently issued a license to an applicant who had not yet passed the state exam","The licensee fails to complete post-licensing education requirements within the first renewal period","The Real Estate Recovery Fund pays a claim on behalf of the licensee"}	1	{"correct": "Revocation without prejudice is an administrative action used when a license was issued in error (by mistake) through no fault of the licensee. It simply cancels the license because it never should have existed in the first place, but it does not carry the stigma of disciplinary \\"punishment.\\" The individual can fix the error (e.g., pass the test) and reapply.", "incorrect": ["A fair housing violation is a serious offense that would lead to disciplinary penalties, likely suspension or permanent revocation (with prejudice).", "", "Failure to complete post-licensing education causes the license to become null and void, not revoked without prejudice.", "A payout from the Recovery Fund results in a mandatory suspension of the license, not revocation without prejudice."]}	9	chapter	2026-03-04 23:05:28.976	2026-03-04 23:37:15.683	\N	\N	\N	\N	/audio/1772667431391-Revocation_without_p.mp3	/timestamps/1772667431391-Revocation_without_p.timestamps.json	["/audio/1772667432872-A_fair_housing_viola.mp3", "", "/audio/1772667434373-Failure_to_complete_.mp3", "/audio/1772667435503-A_payout_from_the_Re.mp3"]	["/timestamps/1772667432872-A_fair_housing_viola.timestamps.json", "", "/timestamps/1772667434373-Failure_to_complete_.timestamps.json", "/timestamps/1772667435503-A_payout_from_the_Re.timestamps.json"]	["/audio/1772667424610-The_licensee_is_foun.mp3", "/audio/1772667425864-The_DBPR_inadvertent.mp3", "/audio/1772667427458-The_licensee_fails_t.mp3", "/audio/1772667428319-The_Real_Estate_Reco.mp3"]	["/timestamps/1772667424610-The_licensee_is_foun.timestamps.json", "/timestamps/1772667425864-The_DBPR_inadvertent.timestamps.json", "/timestamps/1772667427458-The_licensee_fails_t.timestamps.json", "/timestamps/1772667428319-The_Real_Estate_Reco.timestamps.json"]	/audio/1772667423801-Which_of_the_followi.mp3	/timestamps/1772667423801-Which_of_the_followi.timestamps.json
cmmcncehw002z3v0206kxgs0x	cmm58y7lt002j3t2wepydt1xl	After a formal hearing, the Administrative Law Judge (ALJ) issues a Recommended Order. If the licensee disagrees with a "Finding of Fact" in that order, what is the proper procedure to challenge it before the FREC issues a final ruling?&nbsp;	{"Request a new trial with a different judge immediately","File \\"Written Exceptions\\" to the Recommended Order within the statutory time limit","Sue the DBPR in civil court for defamation","Appeal directly to the District Court of Appeals before the FREC meets"}	1	{"correct": "If a party (the licensee or the DBPR) disagrees with the ALJ’s findings or legal conclusions, they may file Written Exceptions. This alerts the FREC to the specific errors the party believes the Judge made, so the FREC can consider them before making the final decision.", "incorrect": ["You cannot simply demand a new trial just because you dislike the outcome.", "", "Civil lawsuits happen separately; they are not part of the administrative disciplinary process.", "You cannot appeal to the Court of Appeals until after the FREC has issued its Final Order. You cannot skip the FREC step."]}	10	chapter	2026-03-04 23:07:05.443	2026-03-04 23:37:28.566	\N	\N	\N	\N	/audio/1772667444954-If_a_party__the_lice.mp3	/timestamps/1772667444954-If_a_party__the_lice.timestamps.json	["/audio/1772667445890-You_cannot_simply_de.mp3", "", "/audio/1772667446914-Civil_lawsuits_happe.mp3", "/audio/1772667448157-You_cannot_appeal_to.mp3"]	["/timestamps/1772667445890-You_cannot_simply_de.timestamps.json", "", "/timestamps/1772667446914-Civil_lawsuits_happe.timestamps.json", "/timestamps/1772667448157-You_cannot_appeal_to.timestamps.json"]	["/audio/1772667439586-Request_a_new_trial_.mp3", "/audio/1772667440530-File__Written_Except.mp3", "/audio/1772667441449-Sue_the_DBPR_in_civi.mp3", "/audio/1772667442261-Appeal_directly_to_t.mp3"]	["/timestamps/1772667439586-Request_a_new_trial_.timestamps.json", "/timestamps/1772667440530-File__Written_Except.timestamps.json", "/timestamps/1772667441449-Sue_the_DBPR_in_civi.timestamps.json", "/timestamps/1772667442261-Appeal_directly_to_t.timestamps.json"]	/audio/1772667438791-After_a_formal_heari.mp3	/timestamps/1772667438791-After_a_formal_heari.timestamps.json
cmmqglhjq003k4be704qj43he	cmmqbpz7v00044be7x0za79d7	Under Florida law, an active duty military service member may terminate their lease early without penalty if:	{"They simply decide to move off-base","They receive a change of station orders 35 miles or more away","They get married","The rent increases by 5%"}	1	{"correct": "A service member can terminate the rental agreement if they receive permanent change of station orders 35 miles or more from the rental premises (or are deployed for 90+ days).", "incorrect": ["This is not a valid legal reason for breaking a lease under the military clause.", "", "This is not a valid legal reason for breaking a lease under the military clause.", "This is not a valid legal reason for breaking a lease under the military clause."]}	20	chapter	2026-03-14 15:06:58.403	2026-03-14 23:14:24.329	\N	\N	\N	\N	/audio/1773530060734-A_service_member_can.mp3	/timestamps/1773530060734-A_service_member_can.timestamps.json	["/audio/1773530062116-This_is_not_a_valid_.mp3", "", "/audio/1773530063196-This_is_not_a_valid_.mp3", "/audio/1773530064177-This_is_not_a_valid_.mp3"]	["/timestamps/1773530062116-This_is_not_a_valid_.timestamps.json", "", "/timestamps/1773530063196-This_is_not_a_valid_.timestamps.json", "/timestamps/1773530064177-This_is_not_a_valid_.timestamps.json"]	["/audio/1773530056312-They_simply_decide_t.mp3", "/audio/1773530057354-They_receive_a_chang.mp3", "/audio/1773530057929-They_get_married.mp3", "/audio/1773530058605-The_rent_increases_b.mp3"]	["/timestamps/1773530056312-They_simply_decide_t.timestamps.json", "/timestamps/1773530057354-They_receive_a_chang.timestamps.json", "/timestamps/1773530057929-They_get_married.timestamps.json", "/timestamps/1773530058605-The_rent_increases_b.timestamps.json"]	/audio/1773530055326-Under_Florida_law__a.mp3	/timestamps/1773530055326-Under_Florida_law__a.timestamps.json
cmmqgn7e8003m4be7lrq2itmq	cmmqbpz7v00044be7x0za79d7	When a tenant vacates a rental unit, the landlord holds the security deposit. If the landlord does NOT intend to make a claim on the deposit, how soon must they return it?	{"15 days","30 days","7 days","45 days"}	0	{"correct": "If there is no claim for damages, the landlord must return the full deposit within 15 days.", "incorrect": ["", "30 days is the deadline if they are making a claim.", "This is an incorrect timeframe.", "This is an incorrect timeframe."]}	21	chapter	2026-03-14 15:08:18.608	2026-03-14 23:14:33.348	\N	\N	\N	\N	/audio/1773530070346-If_there_is_no_claim.mp3	/timestamps/1773530070346-If_there_is_no_claim.timestamps.json	["", "/audio/1773530071585-30_days_is_the_deadl.mp3", "/audio/1773530072330-This_is_an_incorrect.mp3", "/audio/1773530073077-This_is_an_incorrect.mp3"]	["", "/timestamps/1773530071585-30_days_is_the_deadl.timestamps.json", "/timestamps/1773530072330-This_is_an_incorrect.timestamps.json", "/timestamps/1773530073077-This_is_an_incorrect.timestamps.json"]	["/audio/1773530066936-15_days.mp3", "/audio/1773530067581-30_days.mp3", "/audio/1773530068218-7_days.mp3", "/audio/1773530068863-45_days.mp3"]	["/timestamps/1773530066936-15_days.timestamps.json", "/timestamps/1773530067581-30_days.timestamps.json", "/timestamps/1773530068218-7_days.timestamps.json", "/timestamps/1773530068863-45_days.timestamps.json"]	/audio/1773530066305-When_a_tenant_vacate.mp3	/timestamps/1773530066305-When_a_tenant_vacate.timestamps.json
cmmcned5v00313v02xse06huf	cmm58y7lt002j3t2wepydt1xl	A licensee and the DBPR attorney agree to a "settlement stipulation" to resolve a disciplinary case without a hearing. Which body must approve this agreement for it to become effective?	{"DBPR Secretary","The Division of Administrative Hearings (DOAH)","The Florida Real Estate Commission (FREC)","The Probable-Cause Panel"}	2	{"correct": "A stipulation is like a plea bargain. It is a negotiated settlement between the licensee and the DBPR's attorney. However, it is not final until the FREC votes to approve it during a commission meeting.", "incorrect": ["The DBPR Secretary does not approve stipulations.", "The DOAH handles formal hearings, not settlements.", "", "The Probable-Cause Panel starts the case, but they do not approve the final settlement."]}	11	chapter	2026-03-04 23:08:37.027	2026-03-04 23:37:38.544	\N	\N	\N	\N	/audio/1772667455801-A_stipulation_is_lik.mp3	/timestamps/1772667455801-A_stipulation_is_lik.timestamps.json	["/audio/1772667456702-The_DBPR_Secretary_d.mp3", "/audio/1772667457426-The_DOAH_handles_for.mp3", "", "/audio/1772667458368-The_Probable_Cause_P.mp3"]	["/timestamps/1772667456702-The_DBPR_Secretary_d.timestamps.json", "/timestamps/1772667457426-The_DOAH_handles_for.timestamps.json", "", "/timestamps/1772667458368-The_Probable_Cause_P.timestamps.json"]	["/audio/1772667451795-DBPR_Secretary.mp3", "/audio/1772667452560-The_Division_of_Admi.mp3", "/audio/1772667453318-The_Florida_Real_Est.mp3", "/audio/1772667453949-The_Probable_Cause_P.mp3"]	["/timestamps/1772667451795-DBPR_Secretary.timestamps.json", "/timestamps/1772667452560-The_Division_of_Admi.timestamps.json", "/timestamps/1772667453318-The_Florida_Real_Est.timestamps.json", "/timestamps/1772667453949-The_Probable_Cause_P.timestamps.json"]	/audio/1772667450545-A_licensee_and_the_D.mp3	/timestamps/1772667450545-A_licensee_and_the_D.timestamps.json
cmmcng5i700333v020hbcpvw3	cmm58y7lt002j3t2wepydt1xl	If the licensee does NOT dispute the material facts, and the case is heard by the FREC in an informal hearing. In this informal hearing, which members of the FREC are excused from voting?	{"The consumer members","The members of the probable-cause panel","The Chairperson and Vice-Chairperson","No one; all members must vote"}	1	{"correct": "The two members who served on the probable-cause panel for that specific case are always excused from the final hearing (whether informal or formal). This ensures fairness, as they have already formed an opinion by directing the complaint to be filed.", "incorrect": ["All other available members participate in the final decision.", "", "All other available members participate in the final decision.", "All other available members participate in the final decision.&nbsp;"]}	12	chapter	2026-03-04 23:10:00.415	2026-03-04 23:37:50.803	\N	\N	\N	\N	/audio/1772667467349-The_two_members_who_.mp3	/timestamps/1772667467349-The_two_members_who_.timestamps.json	["/audio/1772667468749-All_other_available_.mp3", "", "/audio/1772667469702-All_other_available_.mp3", "/audio/1772667470542-All_other_available_.mp3"]	["/timestamps/1772667468749-All_other_available_.timestamps.json", "", "/timestamps/1772667469702-All_other_available_.timestamps.json", "/timestamps/1772667470542-All_other_available_.timestamps.json"]	["/audio/1772667462558-The_consumer_members.mp3", "/audio/1772667463455-The_members_of_the_p.mp3", "/audio/1772667464595-The_Chairperson_and_.mp3", "/audio/1772667465251-No_one__all_members_.mp3"]	["/timestamps/1772667462558-The_consumer_members.timestamps.json", "/timestamps/1772667463455-The_members_of_the_p.timestamps.json", "/timestamps/1772667464595-The_Chairperson_and_.timestamps.json", "/timestamps/1772667465251-No_one__all_members_.timestamps.json"]	/audio/1772667461847-If_the_licensee_does.mp3	/timestamps/1772667461847-If_the_licensee_does.timestamps.json
